// ── Fix 5: ErrorBoundary — প্রতিটি tab crash isolate করে ──────────────────────
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }
  componentDidCatch(error, info) {
    console.error("[ErrorBoundary] Tab crash caught:", error, info?.componentStack || "");
  }
  render() {
    if (this.state.hasError) {
      const T = this.props.T || {};
      const bg   = T.card  || "#111827";
      const text = T.text  || "#f1f5f9";
      const sub  = T.sub   || "#94a3b8";
      return (
        <div style={{ padding: 32, textAlign: "center", color: text, background: bg, borderRadius: 16, margin: 16 }}>
          <div style={{ fontSize: 44, marginBottom: 12 }}>⚠️</div>
          <div style={{ fontWeight: 800, fontSize: 17, marginBottom: 8 }}>
            এই পেজে একটি সমস্যা হয়েছে
          </div>
          <div style={{ fontSize: 12, color: sub, marginBottom: 20, wordBreak: "break-word", maxWidth: 320, margin: "0 auto 20px" }}>
            {this.state.error?.message || "অজানা ত্রুটি"}
          </div>
          <button
            style={{ background: "#0ea5e9", color: "#fff", border: "none", borderRadius: 10, padding: "11px 24px", fontWeight: 700, fontSize: 14, cursor: "pointer" }}
            onClick={() => this.setState({ hasError: false, error: null })}
          >
            🔄 পুনরায় চেষ্টা করুন
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

// ═══════════════════════════════════════════════════════════════════════════════
// 🇧🇩 GLOBAL BENGALI IME SYSTEM — Avro / Ridmik / Gboard সব keyboard smooth
// ═══════════════════════════════════════════════════════════════════════════════
//
// সমস্যার মূল কারণ:
//   Android WebView-এ বাংলা IME (Avro, Ridmik, Gboard Bengali) লেখার সময়
//   React-এর synthetic onChange বাধা দেয়। কারণ:
//   1. React controlled input (value=) IME composition এর মাঝে DOM reset করে
//   2. compositionend Android-এ reliably fire হয় না (বিশেষত Ridmik-এ)
//   3. React 18-এর batching আরো delay তৈরি করে
//
// সমাধান (Tally Hisab approach):
//   • Global MutationObserver + input event interceptor
//   • সব input/textarea-এ automatically attach হয়
//   • React synthetic event bypass করে native DOM event ব্যবহার করে
//   • IME composition চলাকালীন React update suppress করে
//   • composition শেষে একবারই React state update করে
//
// ─── useBanglaInput hook (component-level) ────────────────────────────────────
function useBanglaInput(value, onChange) {
  const setRef = useCallback((el) => {
    if (!el || el._sbmBengali) return;
    el._sbmBengali = true;
    el.value = value ?? "";
    // setter শুধু compositionend + blur + non-composing input এ
    // typing চলাকালীন onChange নেই → re-render নেই → DOM reset নেই
    el.addEventListener("compositionend", () => { onChange(el.value); }, { passive: true });
    el.addEventListener("blur", () => { onChange(el.value); }, { passive: true });
    el.addEventListener("input", (e) => { if (!e.isComposing) onChange(el.value); }, { passive: true });
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  return { ref: setRef, defaultValue: value, onChange: () => {} };
}

// ─── useSmartSearch — World-class search: fuzzy, debounce, Bengali IME-safe ──
// Features: debounce 120ms | Bengali composition-safe | fuzzy match | highlight
function useSmartSearch(onSearch, delay = 120) {
  const timerRef = useRef(null);
  // onSearch সবসময় latest version ধরে রাখো — stale closure সমস্যা দূর করে
  const onSearchRef = useRef(onSearch);
  useEffect(() => { onSearchRef.current = onSearch; }, [onSearch]);

  const setRef = useCallback((el) => {
    if (!el || el._sbmSearch) return;
    el._sbmSearch = true;
    const schedule = (val) => {
      clearTimeout(timerRef.current);
      timerRef.current = setTimeout(() => onSearchRef.current(val), delay);
    };
    // Android WebView-এ compositionstart/end reliably fire হয় না।
    // autocomplete suggestion bar থাকলে সব typing composing state-এ থাকে।
    // তাই composingRef বাদ দিয়ে সরাসরি input event-এ search করো।
    // compositionend-এও করো যাতে Bengali word commit হলে সাথে সাথে search হয়।
    el.addEventListener("compositionend", (e) => { schedule(e.target.value); }, { passive: true });
    el.addEventListener("input", (e) => { schedule(e.target.value); }, { passive: true });
    el.addEventListener("keydown", (e) => { if (e.key === "Escape") { el.value = ""; onSearchRef.current(""); } }, { passive: true });
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => () => { clearTimeout(timerRef.current); }, []);
  return { ref: setRef, defaultValue: "", onChange: () => {} };
}

// alias for backward compat
const useBanglaSearch = useSmartSearch;

// ─── parseBatchNum — বাংলা ও ইংরেজি সংখ্যা দুটোই handle করে ─────────────────
// "ব্যাচ-1" → 1, "ব্যাচ-১" → 1, "batch-2" → 2, "ব্যাচ-0" → 0
function parseBatchNum(batchStr) {
  if (!batchStr) return 0;
  const bnMap = { "০":0,"১":1,"২":2,"৩":3,"৪":4,"৫":5,"৬":6,"৭":7,"৮":8,"৯":9 };
  // বাংলা সংখ্যা → ইংরেজি
  const normalized = batchStr.replace(/[০-৯]/g, d => bnMap[d] ?? d);
  const num = parseInt(normalized.replace(/[^0-9]/g, ""), 10);
  return isNaN(num) ? 0 : num;
}

// ─── calcNextBatch — Option B: Date-based B-YYMM-N format ───────────────────
// ক্রয়ের তারিখ থেকে B-YYMM-N ফরম্যাটে ব্যাচ আইডি জেনারেট করে
// একই মাসে একাধিক ক্রয়: B-2506-1, B-2506-2, ...
function calcNextBatch(productId, products, purchaseOrders, purchaseDate) {
  const now = purchaseDate ? new Date(purchaseDate) : new Date();
  const yy = String(now.getFullYear()).slice(2);
  const mm = String(now.getMonth() + 1).padStart(2, "0");
  const prefix = `B-${yy}${mm}-`;

  const peEntries = (purchaseOrders || []).filter(e =>
    e._type === "pe" && e.productId === productId
  );
  const prod = (products || []).find(p => p.id === productId);
  const batchBatches = (prod?.batches || []).map(b => b.batchNo || "");

  const allBatchIds = [
    ...peEntries.map(e => e.batch || ""),
    ...batchBatches,
  ];
  const thisMonthNums = allBatchIds
    .filter(b => b.startsWith(prefix))
    .map(b => parseInt(b.slice(prefix.length), 10))
    .filter(n => !isNaN(n));

  const nextN = thisMonthNums.length > 0 ? Math.max(...thisMonthNums) + 1 : 1;
  return `${prefix}${nextN}`;
}

// ─── getSortedActiveBatches — p.batches থেকে FIFO অর্ডারে সব active (qty>0) batch ──
// productBatchMap, prodBatchMap, এবং বিক্রয়ের সময় stock deduction — সব একই sort logic ব্যবহার করে
function getSortedActiveBatches(product) {
  if (!product?.batches || product.batches.length === 0) return [];
  return product.batches
    .filter(b => (b.qty || 0) > 0)
    .sort((a, b) => {
      if (a.expiryDate && b.expiryDate) return new Date(a.expiryDate) - new Date(b.expiryDate);
      if (a.expiryDate) return -1;
      if (b.expiryDate) return 1;
      return new Date(a.at || 0) - new Date(b.at || 0);
    });
}

// ─── getActiveBatch — p.batches থেকে FIFO active batch (qty>0) ──────────────
// productBatchMap ও prodBatchMap উভয়ের shared helper
function getActiveBatch(product) {
  const active = getSortedActiveBatches(product);
  return active[0] || null;
}

// ─── smartMatch — fuzzy/contains scorer for Bengali+English ───────────────────
// Returns: 2=exact start, 1=contains/fuzzy, 0=no match
function smartMatch(text, query) {
  if (!query || !text) return query ? 0 : 1;
  const t = text.toLowerCase();
  const q = query.toLowerCase().trim();
  if (!q) return 1;
  if (t === q) return 3;
  if (t.startsWith(q)) return 2;
  if (t.includes(q)) return 1;
  // fuzzy: all chars of q appear in t in order
  let ti = 0, qi = 0;
  while (ti < t.length && qi < q.length) {
    if (t[ti] === q[qi]) qi++;
    ti++;
  }
  return qi === q.length ? 0.5 : 0;
}

// ─── HighlightText — query match এর অংশ highlight করে ──────────────────────
function HighlightText({ text, query, style, highlightColor = "#22c55e" }) {
  if (!query || !query.trim()) return <span style={style}>{text}</span>;
  const q = query.trim();
  const idx = text.toLowerCase().indexOf(q.toLowerCase());
  if (idx === -1) return <span style={style}>{text}</span>;
  return (
    <span style={style}>
      {text.slice(0, idx)}
      <span style={{ background: highlightColor + "44", color: highlightColor, fontWeight: 800, borderRadius: 3, padding: "0 1px" }}>
        {text.slice(idx, idx + q.length)}
      </span>
      {text.slice(idx + q.length)}
    </span>
  );
}

// ─── SearchBar — reusable smart search input component ───────────────────────
function SearchBar({ placeholder, value, onChange, onClear, color = "#22c55e", T, S, style, voiceColor, showCount, count, accentBorder, autoFocus }) {
  const [focused, setFocused] = React.useState(false);
  const inputRef = React.useRef(null);
  const { ref: smartRef } = useSmartSearch(onChange, 100);

  const setRef = React.useCallback((el) => {
    inputRef.current = el;
    smartRef(el);
    if (el && autoFocus) setTimeout(() => el.focus(), 100);
  }, [smartRef, autoFocus]);

  const borderColor = focused ? color : (accentBorder || color + "44");
  const glowShadow  = focused ? `0 0 0 2.5px ${color}22, 0 2px 16px ${color}18` : `0 1px 4px rgba(0,0,0,0.15)`;

  return (
    <div style={{
      display: "flex", alignItems: "center", gap: 8,
      background: `linear-gradient(135deg,${color}08,${color}04)`,
      border: `1.5px solid ${borderColor}`,
      borderRadius: 14,
      padding: "9px 12px",
      transition: "all 0.2s cubic-bezier(0.4,0,0.2,1)",
      boxShadow: glowShadow,
      ...style,
    }}>
      {/* Search icon — pulses when focused */}
      <svg width="15" height="15" viewBox="0 0 24 24" fill="none"
        stroke={focused ? color : (S?.sub ? "#6b7280" : "#94a3b8")} strokeWidth="2.5" strokeLinecap="round"
        style={{ flexShrink: 0, transition: "stroke 0.2s", opacity: focused ? 1 : 0.7 }}>
        <circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/>
      </svg>

      <input
        ref={setRef}
        defaultValue={value}
        onChange={() => {}}
        placeholder={showCount && count !== undefined ? `${placeholder} (${count})` : placeholder}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        autoCorrect="off" autoCapitalize="off" spellCheck={false} autoComplete="off"
        inputMode="text"
        style={{
          flex: 1, background: "none", border: "none", outline: "none",
          color: T?.text || "#f1f5f9",
          fontSize: 13,
          fontFamily: "inherit",
          padding: 0,
          "::placeholder": { color: T?.sub || "#94a3b8" },
        }}
      />

      {/* Clear button — fades in when there's a value */}
      {value && (
        <button
          onPointerDown={e => { e.preventDefault(); }}
          onClick={() => { if (inputRef.current) { inputRef.current.value = ""; inputRef.current.focus(); } onClear?.(); onChange(""); }}
          style={{ background: color + "22", border: "none", color: color, cursor: "pointer", borderRadius: 8, width: 22, height: 22, fontSize: 11, fontWeight: 800, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0, transition: "all 0.15s" }}>
          ✕
        </button>
      )}

      {/* Voice button slot */}
      {voiceColor && <VoiceSearchButton onResult={onChange} color={voiceColor} />}
    </div>
  );
}

// ─── Global Bengali Input Interceptor ────────────────────────────────────────
// Ridmik/Avro Android-এ compositionupdate fire হয় না।
// input event fire হয় isComposing=true সহ — React controlled input তখন
// DOM reset করে। Fix: React fiber থেকে onChange ধরে call করি, তারপর
// requestAnimationFrame-এ DOM value restore করি।
function installGlobalBengaliInterceptor() {
  if (window._sbmGlobalIME) return;
  window._sbmGlobalIME = true;

  function getReactOnChange(el) {
    const key = Object.keys(el).find(k => k.startsWith("__reactFiber") || k.startsWith("__reactInternalInstance"));
    if (!key) return null;
    let fiber = el[key];
    while (fiber) {
      const onChange = fiber.memoizedProps?.onChange;
      if (typeof onChange === "function") return onChange;
      fiber = fiber.return;
    }
    return null;
  }

  function getNativeSetter(el) {
    return Object.getOwnPropertyDescriptor(
      el.tagName === "TEXTAREA" ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype, "value"
    )?.set;
  }

  function patch(el) {
    if (el._sbmIME) return;
    if (!el.matches("input[type='text'], input:not([type]), textarea")) return;
    el._sbmIME = true;

    // Ridmik অভ্র phonetic mode: composition চলাকালীন pending text
    // WebView InputConnection দিয়ে সরাসরি render হয় — কিন্তু Android WebView
    // একটা bug আছে: compositionupdate-এ pending text DOM-এ থাকলেও
    // visually render হয় না যতক্ষণ না repaint trigger হয়।
    // Fix: compositionupdate-এ opacity flicker দিয়ে force repaint করো।
    el.addEventListener("compositionupdate", () => {
      // Force WebView repaint — opacity 1 থেকে 0.999 তারপর আবার 1
      // এটা GPU layer invalidate করে pending text visible করে
      el.style.opacity = "0.999";
      requestAnimationFrame(() => { el.style.opacity = ""; });
    }, { passive: true });
  }

  document.querySelectorAll("input, textarea").forEach(patch);
  new MutationObserver(ms => ms.forEach(m => m.addedNodes.forEach(n => {
    if (n.nodeType !== 1) return;
    if (n.matches?.("input, textarea")) patch(n);
    n.querySelectorAll?.("input, textarea").forEach(patch);
  }))).observe(document.body, { childList: true, subtree: true });
}

// ─── Global Auto-Capitalize (English first letter) ─────────────────────────
// সব input/textarea-তে ইংরেজি লেখার সময় প্রথম অক্ষর স্বয়ংক্রিয়ভাবে বড় হাতের
// (capital) হয়ে যাবে। বাংলা টাইপিং, সংখ্যা, এবং number/password টাইপ ইনপুট
// এর উপর কোনো প্রভাব পড়বে না।
function installGlobalAutoCapitalize() {
  if (window._sbmAutoCap) return;
  window._sbmAutoCap = true;

  function getNativeSetter(el) {
    return Object.getOwnPropertyDescriptor(
      el.tagName === "TEXTAREA" ? HTMLTextAreaElement.prototype : HTMLInputElement.prototype, "value"
    )?.set;
  }

  // React 16+ controlled input-এ programmatically value বদলালে React-এর
  // internal "_valueTracker" ও রিসেট করতে হয় — নাহলে React মনে করে value
  // বদলায়নি (তার নিজের cache অনুযায়ী "আগেই এই value ছিল"), ফলে পরের
  // synthetic event/re-render এ আগের (lowercase) value ফিরিয়ে আনে।
  function resetReactValueTracker(el) {
    try {
      const tracker = el._valueTracker;
      if (tracker) tracker.setValue("");
    } catch (_) {}
  }

  document.addEventListener("input", (e) => {
    const el = e.target;
    if (!el || (el.tagName !== "INPUT" && el.tagName !== "TEXTAREA")) return;
    if (el.tagName === "INPUT") {
      const t = (el.type || "text").toLowerCase();
      // শুধু free-text টাইপের বক্সে কাজ করবে — number/password/date/email-pattern-sensitive বক্স বাদ
      if (!["text", "search", "tel", "url"].includes(t)) return;
    }
    if (e.isComposing) return; // বাংলা IME composition চলাকালীন স্কিপ — অভ্র/রিদ্মিক ভাঙবে না
    const val = el.value;
    if (!val) return;
    const first = val[0];
    if (first < "a" || first > "z") return; // ইংরেজি ছোট হাতের অক্ষর না হলে কিছু করার নেই
    const corrected = first.toUpperCase() + val.slice(1);
    if (corrected === val) return; // ইতিমধ্যে capital — কিছু করার দরকার নেই
    const pos = el.selectionStart, posEnd = el.selectionEnd;
    const setter = getNativeSetter(el);
    resetReactValueTracker(el);
    if (setter) setter.call(el, corrected); else el.value = corrected;
    try { el.setSelectionRange(pos, posEnd); } catch (_) {}
    // React-কে জানাতে সবসময় bubbling native "input" event dispatch করি —
    // fiber walk করে সরাসরি onChange কল করাটা অনির্ভরযোগ্য কারণ React
    // internal synthetic event object আশা করে যা আমরা বানাতে পারি না।
    el.dispatchEvent(new Event("input", { bubbles: true }));
  }, true);
}

// ─── bnRef: Bengali IME-safe ref helper ──────────────────────────────────────
// setter শুধু compositionend + blur + non-composing input এ — typing এ re-render নেই
function bnRef(setter) {
  return (el) => {
    if (!el || el._sbmBengali) return;
    el._sbmBengali = true;
    el.addEventListener("compositionend", () => { setter(el.value); }, { passive: true });
    el.addEventListener("blur", () => { setter(el.value); }, { passive: true });
    el.addEventListener("input", (e) => { if (!e.isComposing) setter(el.value); }, { passive: true });
  };
}
