// ─── Device ID Layer (Multi-Device Support) ───────────────────────────────────
// প্রতিটি ডিভাইসের আলাদা ID, যাতে ৫টি ডিভাইস একসাথে সিঙ্ক করতে পারে
// 🔥 ফিক্স: শুধু raw localStorage ব্যবহার করায় Capacitor WebView-তে মাঝে মাঝে
// id হারিয়ে যেতো (প্রতিবার নতুন id তৈরি হতো — Active Devices লিস্টে duplicate দেখাতো)।
// এখন app বুট হওয়ার সময় IndexedDB-ভিত্তিক প্রধান storage থেকেও restore/sync করা হয়।
const DeviceID = (() => {
  const KEY = "sbm-device-id";
  let _id = null;
  return {
    get() {
      if (_id) return _id;
      try {
        let id = localStorage.getItem(KEY);
        if (!id) {
          id = "dev_" + Math.random().toString(36).slice(2, 10) + "_" + Date.now().toString(36);
          localStorage.setItem(KEY, id);
        }
        _id = id;
        return id;
      } catch { return "dev_default"; }
    },
    // app বুট হওয়ার সময় একবার কল করা হয় — IndexedDB-তে আগে থেকে id থাকলে সেটাই
    // ব্যবহার করে (localStorage-এ হারিয়ে গেলেও), না থাকলে বর্তমান id IndexedDB-তেও সেভ করে।
    async init() {
      try {
        const stored = await load("sbm-device-id-persistent");
        if (stored && typeof stored === "string") {
          _id = stored;
          try { localStorage.setItem(KEY, stored); } catch {}
        } else {
          const current = this.get();
          await save("sbm-device-id-persistent", current);
        }
      } catch {}
    }
  };
})();

// ─── RT — Real-time Multi-Device Sync Layer (Firebase RTDB SDK, onValue) ─────
// সব ডিভাইস (admin + staff) একই sbm/data/{key} path দেখে। কেউ লিখলে onValue
// listener দিয়ে সব ডিভাইসে সাথে সাথেই (polling ছাড়া) পৌঁছায়।
// Keys synced: customers, products, invoices, txns, smsLog, users, suppliers,
// purchaseOrders, stockMovements, cashLogs, paymentInvoices, shopName,
// smsTemplates, smsGateway
const RT_KEYS = [
  "customers", "products", "invoices", "txns", "smsLog", "users", "suppliers",
  "purchaseOrders", "stockMovements", "cashLogs", "paymentInvoices",
  "shopName", "smsTemplates", "smsGateway",
];

const RT = {
  _app: null,
  _db: null,
  _cfg: null,
  _listeners: {},     // key -> unsubscribe fn
  _echoGuard: {},      // key -> last value JSON this device itself wrote (skip re-applying it)
  _connectionState: "offline",

  isReady() { return !!this._db; },

  // (Re)initialise the RTDB app for a given shop config. Safe to call repeatedly —
  // if config unchanged, no-op; if changed, tears down old app + listeners first.
  init(cfg) {
    if (!cfg?.databaseURL) return false;
    const same = this._cfg && this._cfg.databaseURL === cfg.databaseURL
      && this._cfg.apiKey === cfg.apiKey && this._cfg.projectId === cfg.projectId;
    if (same && this._db) return true;

    this.teardown();
    try {
      // Use a named app per databaseURL so this never collides with the
      // default Firestore app (protik-aa991) used for central recovery.
      const appName = "sbm-rtdb-" + (cfg.projectId || "default");
      const existing = getApps().find(a => a.name === appName);
      this._app = existing || initializeApp(cfg, appName);
      this._db = getDatabase(this._app);
      this._cfg = cfg;
      this._connectionState = "online";
      return true;
    } catch (e) {
      this._connectionState = "offline";
      this._db = null;
      return false;
    }
  },

  teardown() {
    this.unsubscribeAll();
    if (this._app) {
      try { deleteApp(this._app); } catch {}
    }
    this._app = null;
    this._db = null;
    this._cfg = null;
  },

  // Subscribe to one key (e.g. "products"). callback(value) fires on every
  // remote change AND once immediately with current value.
  subscribe(key, callback) {
    if (!this._db) return () => {};
    this.unsubscribe(key);
    const r = dbRef(this._db, `sbm/data/${key}`);
    const handler = onValue(r, (snap) => {
      const val = snap.val();
      const json = JSON.stringify(val);
      // Skip applying the echo of our own most-recent write for this key
      if (this._echoGuard[key] !== undefined && this._echoGuard[key] === json) {
        delete this._echoGuard[key];
        return;
      }
      this._connectionState = "online";
      callback(val, key);
    }, (err) => {
      this._connectionState = "offline";
    });
    this._listeners[key] = () => dbOff(r, "value", handler);
    return this._listeners[key];
  },

  unsubscribe(key) {
    if (this._listeners[key]) { this._listeners[key](); delete this._listeners[key]; }
  },

  unsubscribeAll() {
    Object.keys(this._listeners).forEach(k => this.unsubscribe(k));
  },

  // Subscribe to every shared data key at once.
  subscribeAll(onChange) {
    RT_KEYS.forEach(key => this.subscribe(key, (val) => onChange(key, val)));
  },

  // Instantly write a key's full value to Firebase. Marks echoGuard so the
  // listener this device just triggered doesn't re-apply the same data.
  // Guard auto-clears after 5s as a safety net in case the exact echo never
  // arrives (e.g. server-side JSON normalization).
  //
  // ⚠️ Per-key write queue: যদি একই key-তে আগের push এখনো network-এ pending
  // থাকা অবস্থায় নতুন push আসে (যেমন: পণ্য delete করার ৩০০ms-এর মধ্যেই আরেকটা
  // পরিবর্তন), দুটো dbSet() call একসাথে in-flight থাকলে network response
  // out-of-order আসতে পারে — ফলে পুরনো (delete-এর আগের) ডেটা শেষে গিয়ে লেখা
  // হয়ে যায় এবং মুছে ফেলা পণ্য আবার ফিরে আসে। তাই প্রতিটা key-র push
  // একে অপরের পরে সিরিয়ালি (queue করে) পাঠানো হয়, কখনো overlap করে না।
  async push(key, value) {
    if (!this._db) return { ok: false, msg: "Firebase সংযুক্ত নেই" };
    if (!this._writeQueues) this._writeQueues = {};
    const prevInFlight = this._writeQueues[key] || Promise.resolve();
    const run = prevInFlight.then(() => this._doPush(key, value));
    // queue chain রাখি কিন্তু এর reject অন্য কারো await-কে যেন না আটকায়
    this._writeQueues[key] = run.catch(() => {});
    return run;
  },

  async _doPush(key, value) {
    try {
      const json = JSON.stringify(value === undefined ? null : value);
      this._echoGuard[key] = json;
      if (this._echoGuardTimers?.[key]) clearTimeout(this._echoGuardTimers[key]);
      if (!this._echoGuardTimers) this._echoGuardTimers = {};
      this._echoGuardTimers[key] = setTimeout(() => { delete this._echoGuard[key]; }, 5000);
      await dbSet(dbRef(this._db, `sbm/data/${key}`), value === undefined ? null : value);
      this._connectionState = "online";
      return { ok: true };
    } catch (e) {
      delete this._echoGuard[key];
      this._connectionState = "offline";
      return { ok: false, msg: e.message || "Firebase write ব্যর্থ" };
    }
  },

  // Push multiple keys atomically (one network round-trip).
  async pushMany(obj) {
    if (!this._db) return { ok: false, msg: "Firebase সংযুক্ত নেই" };
    try {
      const updates = {};
      if (!this._echoGuardTimers) this._echoGuardTimers = {};
      Object.entries(obj).forEach(([key, value]) => {
        updates[`sbm/data/${key}`] = value === undefined ? null : value;
        this._echoGuard[key] = JSON.stringify(value === undefined ? null : value);
        if (this._echoGuardTimers[key]) clearTimeout(this._echoGuardTimers[key]);
        this._echoGuardTimers[key] = setTimeout(() => { delete this._echoGuard[key]; }, 5000);
      });
      await dbUpdate(dbRef(this._db), updates);
      this._connectionState = "online";
      return { ok: true };
    } catch (e) {
      this._connectionState = "offline";
      return { ok: false, msg: e.message || "Firebase write ব্যর্থ" };
    }
  },

  // One-time fetch of a key (used for migration / manual checks).
  async getOnce(key) {
    if (!this._db) return null;
    try {
      const snap = await dbGet(dbRef(this._db, `sbm/data/${key}`));
      return snap.val();
    } catch { return null; }
  },

  getConnectionState() { return this._connectionState; },

  // Remove the old polling-era snapshot rotation data (sbm/snaps, sbm/idx,
  // sbm/bk) and replace it with a fresh sbm/data/* structure seeded from this
  // device's current local data. Use once when migrating from the old
  // slot-rotation sync system to real-time per-key sync.
  async purgeLegacyAndReseed(localData) {
    if (!this._db) return { ok: false, msg: "Firebase সংযুক্ত নেই" };
    try {
      await dbSet(dbRef(this._db, "sbm/snaps"), null);
      await dbSet(dbRef(this._db, "sbm/idx"), null);
      await dbSet(dbRef(this._db, "sbm/bk"), null);
      await dbSet(dbRef(this._db, "sbm/ctrl"), null);
      const result = await this.pushMany(localData);
      return result;
    } catch (e) {
      return { ok: false, msg: e.message || "Cleanup ব্যর্থ" };
    }
  },

  // Firebase-এর সব ব্যবসায়িক ডেটা মুছে শূন্য থেকে শুরু
  async clearAllData() {
    if (!this._db) return { ok: false, msg: "Firebase সংযুক্ত নেই" };
    try {
      await dbSet(dbRef(this._db, "sbm"), null);
      return { ok: true };
    } catch (e) {
      return { ok: false, msg: e.message || "Firebase clear ব্যর্থ" };
    }
  },
};

// ─── Firebase Realtime Database Layer (Legacy REST — backup/restore/devices) ─
// Uses Firebase REST API — no SDK, works in any browser/WebView
// Rules must be: { "rules": { ".read": true, ".write": true } }
// Multi-device: up to 5 devices can sync simultaneously via Firebase
// NOTE: live multi-device data sync now goes through RT (above) using onValue
// real-time listeners. FB below is kept for manual JSON backup/restore,
// snapshot history list, and device presence tracking in Settings.
const FB = {
  _cfg: null,
  _pollTimer: null,
  _lastSyncAt: null,
  init(cfg) { this._cfg = cfg; },

  _url(path) {
    if (!this._cfg?.databaseURL) return null;
    const base = this._cfg.databaseURL.replace(/\/$/, "");
    return `${base}/${path}.json`;
  },

  // Compress large data by keeping only essentials for backup
  _compressBackup(data) {
    // Store only the arrays needed for restore — skip meta/version overhead
    return {
      c:  data.customers       || [],   // customers
      p:  data.products        || [],   // products
      i:  data.invoices        || [],   // invoices
      t:  data.txns            || [],   // transactions
      s:  data.smsLog          || [],   // sms log
      pi: data.paymentInvoices || [],   // payment invoices
      u:  data.users           || [],   // staff/admin users + permissions
      po: data.purchaseOrders  || [],   // purchase orders
      sm: data.stockMovements  || [],   // stock movements
      at: data.exportedAt,
      v:  "v12"
    };
  },
  _decompressBackup(d) {
    if (!d) return null;
    // Handle both compressed (v11/v12) and legacy full format
    if (d.c !== undefined) {
      return {
        customers: d.c, products: d.p, invoices: d.i,
        txns: d.t, smsLog: d.s, paymentInvoices: d.pi,
        users: d.u || [], purchaseOrders: d.po || [], stockMovements: d.sm || [],
        exportedAt: d.at, version: d.v
      };
    }
    return d; // legacy full format
  },

  async get(path) {
    const url = this._url(path); if (!url) return null;
    try {
      const r = await fetch(url, { method: "GET" });
      if (!r.ok) return null;
      const j = await r.json();
      return j === null ? null : j;
    } catch { return null; }
  },

  // ── Chunked PUT helper ─────────────────────────────────────────────────────
  // Firebase RTDB REST limit: ~10MB per node, but safe per-request = 900KB.
  // For large arrays (invoices, txns) we split into numbered sub-nodes and
  // write a manifest so the reader can reassemble them.
  //
  //  sbm/bk/<key>          → manifest  { _chunked: true, total: N, at, v }
  //  sbm/bk/<key>_c0       → chunk 0 data
  //  sbm/bk/<key>_c1       → chunk 1 data …
  //
  CHUNK_SAFE_BYTES: 800_000,   // 800 KB — comfortable margin under 900 KB

  async _putRaw(path, body) {
    const url = this._url(path); if (!url) return { ok: false, msg: "URL নেই" };
    try {
      const r = await fetch(url, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body
      });
      if (r.ok) return { ok: true };
      const txt = await r.text();
      if (r.status === 403) {
        if (txt.includes("host") || txt.includes("allowlist"))
          return { ok: false, msg: "Rules বন্ধ: Firebase Console → Realtime Database → Rules → .read/.write: true করুন" };
        return { ok: false, msg: `অ্যাক্সেস নেই (403): Rules চেক করুন` };
      }
      return { ok: false, msg: `HTTP ${r.status}: ${txt.slice(0, 60)}` };
    } catch(e) {
      return { ok: false, msg: `নেটওয়ার্ক সমস্যা: ${e.message}` };
    }
  },

  async set(path, data) {
    const body = JSON.stringify(data);

    // ── Fast path: fits in one request ──────────────────────────────────────
    if (body.length <= this.CHUNK_SAFE_BYTES) {
      return this._putRaw(path, body);
    }

    // ── Slow path: split into chunks ─────────────────────────────────────────
    // Split the serialised string into CHUNK_SAFE_BYTES-sized pieces.
    // Each chunk is stored as a plain string under <path>_cN.
    // A manifest node at <path> tells loadBackup how many chunks to fetch.
    const chunks = [];
    for (let i = 0; i < body.length; i += this.CHUNK_SAFE_BYTES) {
      chunks.push(body.slice(i, i + this.CHUNK_SAFE_BYTES));
    }

    // Write all chunk nodes (can be parallelised safely — different paths)
    const writes = await Promise.all(
      chunks.map((chunk, idx) =>
        this._putRaw(`${path}_c${idx}`, JSON.stringify(chunk))
      )
    );
    const failed = writes.find(w => !w.ok);
    if (failed) return failed;

    // Write manifest last — readers check for _chunked flag
    const manifestResult = await this._putRaw(path, JSON.stringify({
      _chunked: true,
      total: chunks.length,
      bytes: body.length,
      at: new Date().toISOString(),
    }));
    if (!manifestResult.ok) return manifestResult;

    return { ok: true, chunked: true, chunks: chunks.length, bytes: body.length };
  },

  async delete(path) {
    const url = this._url(path); if (!url) return;
    try { await fetch(url, { method: "DELETE" }); } catch {}
  },

  // 🗑️ Master Delete — Firebase-এ রাখা সব ব্যাকআপ snapshot (৩টি rotating slot +
  // manifest + legacy path) স্থায়ীভাবে মুছে দেয়। লাইভ ডেটা (sbm/data/*) স্পর্শ করে না।
  async deleteAllBackups() {
    try {
      await Promise.all([
        this.delete("sbm/snaps/manifest"),
        this.delete("sbm/snaps/s1"),
        this.delete("sbm/snaps/s2"),
        this.delete("sbm/snaps/s3"),
        this.delete("sbm/idx"),      // legacy index
        this.delete("sbm/bk"),       // legacy single backup node
      ]);
      return { ok: true };
    } catch (e) {
      return { ok: false, msg: e.message };
    }
  },

  // ── Rolling Snapshot System ────────────────────────────────────────────────
  // Firebase paths:
  //   sbm/snaps/manifest   → { cur: 1, slots: { 1: {at,meta,label}, 2: {...}, 3: {...} } }
  //   sbm/snaps/s1         → compressed data (slot 1)
  //   sbm/snaps/s2         → compressed data (slot 2)
  //   sbm/snaps/s3         → compressed data (slot 3)
  //
  // Rotation: cur cycles 1→2→3→1. Oldest slot is always overwritten.
  // Legacy path sbm/idx + sbm/bk/* still readable for backward compat.
  SNAP_SLOTS: 3,

  async saveBackup(data, filename, label = null) {
    const ts = new Date().toISOString();
    const meta = {
      c: (data.customers||[]).length,
      i: (data.invoices||[]).length,
      t: (data.txns||[]).length,
      p: (data.products||[]).length,
    };

    // 1. Read current manifest (create fresh if missing)
    const manifest = (await this.get("sbm/snaps/manifest")) || { cur: 0, slots: {} };
    const nextSlot = (manifest.cur % this.SNAP_SLOTS) + 1; // 1,2,3,1,2,3...

    // 2. Write compressed data into the next slot
    const compressed = this._compressBackup(data);
    const dataResult = await this.set(`sbm/snaps/s${nextSlot}`, compressed);
    if (!dataResult.ok) return dataResult;

    // 3. Update manifest atomically
    const newManifest = {
      cur: nextSlot,
      slots: {
        ...manifest.slots,
        [nextSlot]: {
          at: ts,
          fn: filename || "backup",
          label: label || `স্ন্যাপশট ${nextSlot}`,
          meta,
          chunked: !!(dataResult.chunked),
        },
      },
    };
    const mResult = await this.set("sbm/snaps/manifest", newManifest);
    if (!mResult.ok) return mResult;

    return { ok: true, slot: nextSlot, at: ts, meta };
  },

  // Load a specific snapshot slot (default: latest)
  async loadBackup(slot = null) {
    const manifest = await this.get("sbm/snaps/manifest");

    // ── New rolling snapshot system ─────────────────────────────────────────
    if (manifest?.cur) {
      const targetSlot = slot || manifest.cur;
      const slotInfo   = manifest.slots?.[targetSlot];
      if (!slotInfo) return { ok: false, msg: `স্লট ${targetSlot} পাওয়া যায়নি` };

      const raw = await this.get(`sbm/snaps/s${targetSlot}`);
      if (!raw) return { ok: false, msg: `স্লট ${targetSlot}-এ ডেটা নেই` };

      // Handle chunked slot data
      if (raw._chunked) {
        const { total } = raw;
        const chunkResults = await Promise.all(
          Array.from({ length: total }, (_, i) => this.get(`sbm/snaps/s${targetSlot}_c${i}`))
        );
        if (chunkResults.some(c => c === null)) {
          return { ok: false, msg: `চাংক পাওয়া যায়নি` };
        }
        try {
          const fullJson = chunkResults.join("");
          const parsed = JSON.parse(fullJson);
          return { ok: true, data: this._decompressBackup(parsed), slot: targetSlot, at: slotInfo.at };
        } catch(e) {
          return { ok: false, msg: `Parse ব্যর্থ: ${e.message}` };
        }
      }
      return { ok: true, data: this._decompressBackup(raw), slot: targetSlot, at: slotInfo.at };
    }

    // ── Legacy fallback: old sbm/idx + sbm/bk/* path ────────────────────
    const idx = await this.get("sbm/idx");
    if (!idx?.k) return { ok: false, msg: "Firebase-এ কোনো ব্যাকআপ নেই" };
    const key = idx.k;
    const legacyData = await this.get(`sbm/bk/${key}`);
    if (!legacyData) return { ok: false, msg: "ব্যাকআপ ডেটা পাওয়া যায়নি" };
    if (legacyData._chunked) {
      const { total } = legacyData;
      const chunkResults = await Promise.all(
        Array.from({ length: total }, (_, i) => this.get(`sbm/bk/${key}_c${i}`))
      );
      if (chunkResults.some(c => c === null))
        return { ok: false, msg: "চাংক পাওয়া যায়নি" };
      try {
        const fullJson = chunkResults.join("");
        return { ok: true, data: this._decompressBackup(JSON.parse(fullJson)), idx };
      } catch(e) {
        return { ok: false, msg: `Parse ব্যর্থ: ${e.message}` };
      }
    }
    return { ok: true, data: this._decompressBackup(legacyData), idx };
  },

  // List all available snapshot slots (for restore UI)
  async listSnapshots() {
    const manifest = await this.get("sbm/snaps/manifest");
    if (!manifest?.slots) {
      // Legacy: return single entry if old-style backup exists
      const idx = await this.get("sbm/idx");
      if (!idx?.k) return [];
      return [{ slot: "legacy", at: idx.at, label: "পুরনো ব্যাকআপ", meta: idx.meta || {}, isCurrent: true }];
    }
    const { cur, slots } = manifest;
    return Object.entries(slots)
      .map(([slot, info]) => ({ slot: parseInt(slot), ...info, isCurrent: parseInt(slot) === cur }))
      .sort((a, b) => new Date(b.at) - new Date(a.at)); // newest first
  },

  // Quick connection test
  async testConnection() {
    const url = this._url("_ping");
    if (!url) return { ok: false, msg: "Database URL দেওয়া নেই" };
    try {
      const r = await fetch(url, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ts: Date.now() })
      });
      if (r.ok) return { ok: true, msg: "🎉 সংযোগ সফল! Firebase প্রস্তুত।" };
      const txt = await r.text();
      if (r.status === 403) {
        if (txt.includes("host") || txt.includes("allowlist")) {
          return { ok: false, msg: "❌ Rules বন্ধ আছে। Firebase Console → Realtime Database → Rules ট্যাব → নিচের Rules লিখে Publish করুন" };
        }
        return { ok: false, msg: `❌ অ্যাক্সেস নেই (403) — Rules চেক করুন` };
      }
      return { ok: false, msg: `❌ HTTP ${r.status}: ${txt.slice(0,60)}` };
    } catch(e) {
      return { ok: false, msg: `❌ নেটওয়ার্ক সমস্যা: ${e.message}` };
    }
  },

  isReady() { return !!(this._cfg?.databaseURL); },

  // Register this device in Firebase (for multi-device tracking)
  async registerDevice(deviceInfo) {
    const devId = DeviceID.get();
    const url = this._url(`dukan/devices/${devId}`);
    if (!url) return;
    try {
      await fetch(url, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...deviceInfo, devId, lastSeen: Date.now(), active: true })
      });
    } catch {}
  },

  // Get all active devices (within last 24h)
  async getActiveDevices() {
    const data = await this.get("dukan/devices");
    if (!data) return [];
    const now = Date.now();
    const DAY = 24 * 60 * 60 * 1000;
    return Object.values(data).filter(d => d.lastSeen && (now - d.lastSeen) < DAY);
  },

  // Start polling for changes from other devices (every 30s)
  startPolling(onNewData, intervalMs = 30000) {
    if (this._pollTimer) clearInterval(this._pollTimer);
    this._pollTimer = setInterval(async () => {
      try {
        // ── New rolling snapshot path (primary) ────────────────────────────
        const manifest = await this.get("sbm/snaps/manifest");
        if (manifest?.cur && manifest?.slots?.[manifest.cur]?.at) {
          const remoteAt = new Date(manifest.slots[manifest.cur].at).getTime();
          if (!this._lastSyncAt || remoteAt > this._lastSyncAt) {
            const backup = await this.loadBackup();
            if (backup?.ok && backup?.data) {
              this._lastSyncAt = remoteAt;
              if (onNewData) onNewData(backup.data, manifest.slots[manifest.cur].at);
            }
          }
          return; // new path found — skip legacy check
        }

        // ── Legacy fallback: old sbm/idx path ────────────────────────────
        const idx = await this.get("sbm/idx");
        if (!idx?.k || !idx?.at) return;
        const remoteAt = new Date(idx.at).getTime();
        if (!this._lastSyncAt || remoteAt > this._lastSyncAt) {
          const backup = await this.loadBackup();
          if (backup?.ok && backup?.data) {
            this._lastSyncAt = remoteAt;
            if (onNewData) onNewData(backup.data, idx.at);
          }
        }
      } catch {}
    }, intervalMs);
  },

  stopPolling() {
    if (this._pollTimer) { clearInterval(this._pollTimer); this._pollTimer = null; }
  },

  setLastSyncAt(ts) { this._lastSyncAt = ts ? new Date(ts).getTime() : null; }
};

// ─── Dirty Queue — IndexedDB-based Persistent Sync Queue ─────────────────────
// যেসব record sync হয়নি তাদের queue-এ রাখে — offline-এ কাজ করে, online-এ push করে
const DirtyQueue = (() => {
  const DB_NAME  = "hg_dirty_queue";
  const STORE    = "queue";
  let _db = null;

  const open = () => new Promise((res, rej) => {
    if (_db) return res(_db);
    const req = indexedDB.open(DB_NAME, 1);
    req.onupgradeneeded = e => {
      const db = e.target.result;
      if (!db.objectStoreNames.contains(STORE)) {
        db.createObjectStore(STORE, { keyPath: "id" });
      }
    };
    req.onsuccess = e => { _db = e.target.result; res(_db); };
    req.onerror   = e => rej(e.target.error);
  });

  return {
    // Queue-এ record যোগ করো (upsert)
    async enqueue(record) {
      try {
        const db = await open();
        await new Promise((res, rej) => {
          const tx  = db.transaction(STORE, "readwrite");
          const req = tx.objectStore(STORE).put({
            id:        record.id || ("dq_" + Date.now()),
            collection: record.collection,
            data:      record,
            queuedAt:  new Date().toISOString(),
          });
          req.onsuccess = res;
          req.onerror   = () => rej(req.error);
        });
      } catch {}
    },

    // সব pending items পড়ো
    async getAll() {
      try {
        const db = await open();
        return new Promise((res, rej) => {
          const tx  = db.transaction(STORE, "readonly");
          const req = tx.objectStore(STORE).getAll();
          req.onsuccess = () => res(req.result || []);
          req.onerror   = () => rej(req.error);
        });
      } catch { return []; }
    },

    // সফলভাবে sync হওয়া item মুছে দাও
    async remove(id) {
      try {
        const db = await open();
        await new Promise((res, rej) => {
          const tx  = db.transaction(STORE, "readwrite");
          const req = tx.objectStore(STORE).delete(id);
          req.onsuccess = res;
          req.onerror   = () => rej(req.error);
        });
      } catch {}
    },

    // সব clear করো (full sync সফল হলে)
    async clear() {
      try {
        const db = await open();
        await new Promise((res, rej) => {
          const tx = db.transaction(STORE, "readwrite");
          tx.objectStore(STORE).clear();
          tx.oncomplete = res;
          tx.onerror    = () => rej(tx.error);
        });
      } catch {}
    },

    async size() {
      try {
        const all = await this.getAll();
        return all.length;
      } catch { return 0; }
    },
  };
})();

// ─── Sync Log — in-memory ring buffer (last 50 entries) ───────────────────────
// ─── SyncLog — Persistent IndexedDB + in-memory cache ───────────────────────
// In-memory: last 50 entries (fast, reactive)
// IndexedDB:  last 7 days (survives restarts, useful for production debug)
//
// DB schema:
//   DB: "sbm_synclog"  STORE: "logs"  keyPath: "id"  index: "at" (for range queries)
const SyncLog = (() => {
  const MAX_MEM  = 50;          // in-memory limit
  const MAX_DAYS = 7;           // IndexedDB retention
  const DB_NAME  = "sbm_synclog";
  const STORE    = "logs";

  const _entries   = [];        // in-memory cache (newest first)
  const _listeners = new Set();
  let   _db        = null;
  let   _ready     = false;
  let   _queue     = [];        // buffered writes before DB is open

  // ── Open IndexedDB ──────────────────────────────────────────────────────────
  function _openDB() {
    return new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, 1);
      req.onupgradeneeded = e => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains(STORE)) {
          const store = db.createObjectStore(STORE, { keyPath: "id" });
          store.createIndex("at", "at", { unique: false });
        }
      };
      req.onsuccess = e => resolve(e.target.result);
      req.onerror   = () => reject(req.error);
    });
  }

  // ── Flush buffered writes after DB opens ────────────────────────────────────
  async function _init() {
    try {
      _db    = await _openDB();
      _ready = true;
      // Restore recent logs into memory (last MAX_MEM entries)
      const cutoff  = new Date(Date.now() - MAX_DAYS * 86400000).toISOString();
      const all     = await _rangeQuery(cutoff);
      // Populate memory cache (newest first, capped)
      all.sort((a, b) => b.at.localeCompare(a.at)).slice(0, MAX_MEM).forEach(e => _entries.push(e));
      _listeners.forEach(fn => fn([..._entries]));
      // Flush buffered writes
      for (const e of _queue) await _persist(e);
      _queue = [];
      // Prune entries older than MAX_DAYS
      await _prune();
    } catch {
      _ready = true; // degraded: in-memory only
    }
  }

  // ── Write one entry to IndexedDB ────────────────────────────────────────────
  function _persist(entry) {
    if (!_db) return Promise.resolve();
    return new Promise((resolve) => {
      try {
        const tx = _db.transaction(STORE, "readwrite");
        tx.objectStore(STORE).put(entry);
        tx.oncomplete = resolve;
        tx.onerror    = resolve; // non-fatal
      } catch { resolve(); }
    });
  }

  // ── Read entries after a given ISO timestamp ────────────────────────────────
  function _rangeQuery(fromISO) {
    return new Promise((resolve) => {
      if (!_db) { resolve([]); return; }
      try {
        const tx    = _db.transaction(STORE, "readonly");
        const idx   = tx.objectStore(STORE).index("at");
        const range = IDBKeyRange.lowerBound(fromISO);
        const req   = idx.getAll(range);
        req.onsuccess = () => resolve(req.result || []);
        req.onerror   = () => resolve([]);
      } catch { resolve([]); }
    });
  }

  // ── Delete entries older than MAX_DAYS ──────────────────────────────────────
  function _prune() {
    return new Promise((resolve) => {
      if (!_db) { resolve(); return; }
      try {
        const cutoff = new Date(Date.now() - MAX_DAYS * 86400000).toISOString();
        const tx     = _db.transaction(STORE, "readwrite");
        const idx    = tx.objectStore(STORE).index("at");
        const range  = IDBKeyRange.upperBound(cutoff, true);
        const req    = idx.openCursor(range);
        req.onsuccess = e => {
          const cursor = e.target.result;
          if (cursor) { cursor.delete(); cursor.continue(); }
        };
        tx.oncomplete = resolve;
        tx.onerror    = resolve;
      } catch { resolve(); }
    });
  }

  // Kick off DB init (non-blocking)
  if (typeof indexedDB !== "undefined") {
    _init();
  } else {
    _ready = true;
  }

  return {
    add(type, msg, detail = "") {
      const entry = {
        id:     `${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
        type,   // "sync" | "error" | "queue" | "merge" | "info"
        msg,
        detail: detail || "",
        at:     new Date().toISOString(),
      };
      // 1. In-memory (immediate, reactive)
      _entries.unshift(entry);
      if (_entries.length > MAX_MEM) _entries.pop();
      _listeners.forEach(fn => fn([..._entries]));
      // 2. Persist (async, non-blocking)
      if (_ready && _db) {
        _persist(entry);
      } else {
        _queue.push(entry); // buffer until DB ready
      }
    },

    getAll()              { return [..._entries]; },
    subscribe(fn)         { _listeners.add(fn); return () => _listeners.delete(fn); },

    // Load full history from IndexedDB (for "export logs" feature)
    async getHistory(days = MAX_DAYS) {
      const cutoff = new Date(Date.now() - days * 86400000).toISOString();
      const all    = await _rangeQuery(cutoff);
      return all.sort((a, b) => b.at.localeCompare(a.at));
    },

    // Manual prune (e.g. from Settings → Clear Logs)
    async clear() {
      _entries.length = 0;
      _listeners.forEach(fn => fn([]));
      if (!_db) return;
      return new Promise((resolve) => {
        try {
          const tx = _db.transaction(STORE, "readwrite");
          tx.objectStore(STORE).clear();
          tx.oncomplete = resolve;
          tx.onerror    = resolve;
        } catch { resolve(); }
      });
    },
  };
})();

// ═══════════════════════════════════════════════════════════════════════════════
// ─── Vector Clock — lightweight per-device logical clock ─────────────────────
// প্রতিটি device-এর নিজস্ব counter থাকে।
// { "dev_abc": 5, "dev_xyz": 3 } → device abc ৫টি write করেছে
// Causality detection: যদি remote VC local VC-কে dominate করে → remote wins
// Concurrent writes (true conflict) → field-level merge + audit trail
// ═══════════════════════════════════════════════════════════════════════════════
const VectorClock = {
  _KEY: "sbm_vc",

  // এই device-এর current vector clock পড়ো
  get() {
    try { return JSON.parse(localStorage.getItem(this._KEY) || "{}"); } catch { return {}; }
  },

  // এই device-এর counter বাড়াও
  tick() {
    const vc  = this.get();
    const dev = DeviceID.get();
    vc[dev]   = (vc[dev] || 0) + 1;
    try { localStorage.setItem(this._KEY, JSON.stringify(vc)); } catch {}
    return { ...vc };
  },

  // remote VC দিয়ে local VC update করো (merge max)
  merge(remoteVC) {
    if (!remoteVC || typeof remoteVC !== "object") return;
    const local = this.get();
    const merged = { ...local };
    Object.entries(remoteVC).forEach(([dev, cnt]) => {
      merged[dev] = Math.max(merged[dev] || 0, cnt);
    });
    try { localStorage.setItem(this._KEY, JSON.stringify(merged)); } catch {}
  },

  // VC তুলনা:
  //   "dominates" → a সব dimension-এ ≥ b, অন্তত একটায় >
  //   "dominated" → b সব dimension-এ ≥ a, অন্তত একটায় >
  //   "concurrent" → কেউ কাউকে dominate করে না (true conflict)
  //   "equal"     → identical
  compare(vcA, vcB) {
    if (!vcA || !vcB) return "unknown";
    const keysA = Object.keys(vcA), keysB = Object.keys(vcB);
    const allKeys = [...new Set([...keysA, ...keysB])];
    let aGtB = false, bGtA = false;
    for (const k of allKeys) {
      const a = vcA[k] || 0, b = vcB[k] || 0;
      if (a > b) aGtB = true;
      if (b > a) bGtA = true;
    }
    if (aGtB && !bGtA) return "dominates";   // a is newer
    if (bGtA && !aGtB) return "dominated";   // b is newer
    if (!aGtB && !bGtA) return "equal";
    return "concurrent";                       // true conflict
  },
};

// ─── Device Priority — tie-break for concurrent conflicts ─────────────────────
// concurrent conflict হলে priority দিয়ে tie-break করি
// Financial fields-এ (balance, amount) additive merge করি
const DevicePriority = {
  // Priority: numeric value যত বেশি তত বেশি আস্থাযোগ্য
  // Admin device: priority 10, normal: 1
  _KEY: "sbm_dev_priority",
  get()  {
    try { return parseInt(localStorage.getItem(this._KEY) || "1"); } catch { return 1; }
  },
  set(v) { try { localStorage.setItem(this._KEY, String(v)); } catch {} },
};

// ─── Field-Level Merge Strategy ───────────────────────────────────────────────
// প্রতিটি collection-এর জন্য কোন fields কীভাবে merge হবে সেটা define করা আছে
const FIELD_MERGE_RULES = {
  // customers: balance additive নয় (পেমেন্ট independent হওয়ায়), last-write জেতে
  // কিন্তু name/mobile/address: remote জেতে শুধু যদি local পুরনো হয়
  customers: {
    financial: ["balance"],          // higher-value wins (বেশি বাকি = সর্বশেষ state)
    identity:  ["name","mobile","address","area"],  // last-write
    protected: ["id","createdAt"],   // কখনো overwrite হয় না
  },
  // invoices: immutable — একবার তৈরি হলে কোনো field বদলায় না
  invoices: {
    immutable: true,
  },
  // txns: immutable — financial ledger, append-only
  txns: {
    immutable: true,
  },
  // paymentInvoices: immutable
  paymentInvoices: {
    immutable: true,
  },
  // products: stock additive merge, price last-write
  products: {
    additive:  ["stock"],            // দুই device-এর delta যোগ হয়
    financial: ["price","costPrice"], // last-write (timestamp winner)
    identity:  ["name","category","unit","minStockAlert","barcode","expiryDate"],
    protected: ["id","createdAt"],
    // Fix: batches[] timestamp winner নেবে — costPrice সঠিক রাখতে
    arrayMerge: ["batches"],
  },
  // smsLog: append-only, id দিয়ে deduplicate
  smsLog: {
    appendOnly: true,
  },
};

// ─── Enhanced FB — Vector Clock + Field-Level Merge + Batch + Delta ───────────
Object.assign(FB, {
  _batchTimer:      null,
  _batchPending:    {},
  _latencyMs:       null,
  _connectionState: "unknown",
  _conflictLog:     [],   // audit trail of resolved conflicts

  // ── stampRecord: updatedAt + deviceId + vector clock ─────────────────────────
  stampRecord(record, collection) {
    const vc = VectorClock.tick();
    return {
      ...record,
      updatedAt:    new Date().toISOString(),
      updatedBy:    DeviceID.get(),
      _devPriority: DevicePriority.get(),
      _vc:          vc,          // vector clock snapshot at write time
      _collection:  collection,
      synced:       false,
    };
  },

  // ── Field-level merge for a single record ────────────────────────────────────
  // concurrent conflict হলে field-by-field সিদ্ধান্ত নেয়
  _fieldMerge(local, remote, collection) {
    const rules = FIELD_MERGE_RULES[collection] || {};

    // immutable collections → remote append, id দিয়ে deduplicate
    if (rules.immutable) {
      // invoices/txns কখনো overwrite হয় না — newer বেশি নির্ভরযোগ্য
      const localTime  = new Date(local.updatedAt  || 0).getTime();
      const remoteTime = new Date(remote.updatedAt || 0).getTime();
      const winner = remoteTime >= localTime ? remote : local;
      SyncLog.add("merge", `[${collection}] immutable → time-pick (id: ${local.id})`);
      return { ...winner, synced: true, _mergeType: "immutable-time" };
    }

    // appendOnly → remote + local deduplicated by id (handled at collection level)
    if (rules.appendOnly) {
      return { ...remote, synced: true, _mergeType: "appendOnly" };
    }

    // Protected fields: always keep local value
    const protected_ = new Set(rules.protected || []);

    // Start from local as base
    const merged = { ...local };

    // additive fields: delta-based merge
    // Formula: যদি উভয় device-এ stock আলাদাভাবে বেড়ে থাকে,
    // তাহলে দুটোর মধ্যে যেটা বেশি সেটা নাও — কারণ আমরা প্রতিটি
    // stock change delta হিসেবে stockMovements-এ log করি।
    // True delta merge (remote_delta = remote.stock - base) শুধু তখনই
    // সম্ভব যদি _baseStock থাকে; না থাকলে max safe।
    (rules.additive || []).forEach(field => {
      const lv = Number(local[field]  || 0);
      const rv = Number(remote[field] || 0);
      // উভয় device-এ delta track হয় stockMovements-এ।
      // merge: যেটা বেশি সেটা নাও (conservative — stock কমানো বিপজ্জনক)
      merged[field] = Math.max(lv, rv);
      SyncLog.add("merge", `[${collection}] additive field "${field}": max(${lv}, ${rv}) = ${merged[field]}`);
    });

    // financial fields: higher timestamp's value
    const localTime  = new Date(local.updatedAt  || 0).getTime();
    const remoteTime = new Date(remote.updatedAt || 0).getTime();
    const timeWinner = remoteTime >= localTime ? remote : local;
    (rules.financial || []).forEach(field => {
      if (!protected_.has(field)) merged[field] = timeWinner[field];
    });

    // identity fields: same time-winner
    (rules.identity || []).forEach(field => {
      if (!protected_.has(field)) merged[field] = timeWinner[field];
    });

    // Protected: always local
    (rules.protected || []).forEach(field => {
      merged[field] = local[field];
    });

    // arrayMerge fields: timestamp winner নেয় (batches[] সঠিক রাখতে)
    (rules.arrayMerge || []).forEach(field => {
      if (!protected_.has(field)) merged[field] = timeWinner[field] || local[field] || [];
    });

    // Merge vector clocks
    merged._vc       = this._mergeVC(local._vc, remote._vc);
    merged.updatedAt = new Date().toISOString();
    merged.updatedBy = DeviceID.get();
    merged._mergeType = "field-level";
    merged.synced     = false; // merged result needs to be pushed back

    SyncLog.add("merge", `[${collection}] field-level merge complete (id: ${local.id})`);
    return merged;
  },

  _mergeVC(vcA, vcB) {
    if (!vcA && !vcB) return {};
    if (!vcA) return vcB;
    if (!vcB) return vcA;
    const result = { ...vcA };
    Object.entries(vcB).forEach(([k, v]) => {
      result[k] = Math.max(result[k] || 0, v);
    });
    return result;
  },

  // ── mergeRecord — vector clock aware, with field-level fallback ───────────────
  mergeRecord(local, remote, collection = "unknown") {
    if (!local) {
      VectorClock.merge(remote?._vc);
      return remote ? { ...remote, synced: true } : null;
    }
    if (!remote) return local;

    const vcResult = VectorClock.compare(local._vc || {}, remote._vc || {});

    if (vcResult === "equal") {
      SyncLog.add("merge", `[${collection}] VC equal → keep local (id: ${local.id})`);
      return local;
    }

    if (vcResult === "dominates") {
      // local is causally newer → keep local, mark dirty
      SyncLog.add("merge", `[${collection}] local dominates → local wins (id: ${local.id})`);
      return { ...local, synced: false };
    }

    if (vcResult === "dominated") {
      // remote is causally newer → take remote cleanly
      VectorClock.merge(remote._vc);
      SyncLog.add("merge", `[${collection}] remote dominates → remote wins (id: ${local.id})`);
      return { ...remote, synced: true };
    }

    // "concurrent" — true conflict → field-level merge
    SyncLog.add("merge", `[${collection}] CONCURRENT CONFLICT → field-level merge (id: ${local.id})`);

    // Device priority tie-break: higher priority device's timestamp-based fields win
    const localPri  = local._devPriority  || 1;
    const remotePri = remote._devPriority || 1;
    if (localPri !== remotePri) {
      const priorityWinner = localPri > remotePri ? local : remote;
      SyncLog.add("merge", `[${collection}] priority tie-break → dev priority ${Math.max(localPri,remotePri)} wins`);
      VectorClock.merge(priorityWinner._vc);
      return {
        ...priorityWinner,
        _vc:      this._mergeVC(local._vc, remote._vc),
        synced:   priorityWinner === local ? false : true,
        _mergeType: "priority-tiebreak",
      };
    }

    // Same priority → full field-level merge
    const result = this._fieldMerge(local, remote, collection);
    VectorClock.merge(result._vc);

    // Audit trail (last 20 conflicts kept in memory)
    this._conflictLog.unshift({
      id: local.id, collection, at: new Date().toISOString(),
      localTime: local.updatedAt, remoteTime: remote.updatedAt,
      resolution: result._mergeType,
    });
    if (this._conflictLog.length > 20) this._conflictLog.pop();

    return result;
  },

  // ── mergeCollection — appendOnly collections get union-deduplicate ─────────
  mergeCollection(localArr, remoteArr, collection = "unknown") {
    if (!remoteArr?.length) return localArr || [];
    if (!localArr?.length) return remoteArr.map(r => ({ ...r, synced: true }));

    const rules = FIELD_MERGE_RULES[collection] || {};

    // appendOnly: union by id
    if (rules.appendOnly) {
      const seen = new Map((localArr).map(r => [r.id, r]));
      remoteArr.forEach(r => { if (!seen.has(r.id)) seen.set(r.id, { ...r, synced: true }); });
      return Array.from(seen.values());
    }

    const localMap  = new Map(localArr.map(r => [r.id, r]));
    const remoteMap = new Map(remoteArr.map(r => [r.id, r]));

    remoteMap.forEach((remoteRec, id) => {
      const localRec = localMap.get(id);
      localMap.set(id, this.mergeRecord(localRec, remoteRec, collection));
    });

    return Array.from(localMap.values());
  },

  // ── pushDelta — dirty records only ───────────────────────────────────────────
  async pushDelta(allData) {
    if (!this.isReady()) return { ok: false, msg: "Firebase সেট করা নেই" };
    const dirty = {};
    let totalDirty = 0;

    ["customers","products","invoices","txns","paymentInvoices","smsLog"].forEach(col => {
      const arr = allData[col] || [];
      const dirtyRecords = arr.filter(r => r.synced === false || !r.updatedAt);
      if (dirtyRecords.length) {
        dirty[col]  = dirtyRecords;
        totalDirty += dirtyRecords.length;
      }
    });

    if (totalDirty === 0) {
      SyncLog.add("info", "কোনো dirty record নেই — skip");
      return { ok: true, pushed: 0 };
    }

    SyncLog.add("queue", `${totalDirty}টি dirty record push করা হচ্ছে...`);

    for (const [col, records] of Object.entries(dirty)) {
      for (const rec of records) await DirtyQueue.enqueue({ ...rec, collection: col });
    }

    const ts  = new Date().toISOString();
    const key = `delta_${Date.now()}`;
    const r   = await this.set(`dukan/delta/${key}`, {
      data: dirty, deviceId: DeviceID.get(), at: ts, count: totalDirty,
      vc: VectorClock.get(),
    });

    if (r.ok) {
      SyncLog.add("sync", `✓ ${totalDirty}টি record push সফল`);
      await DirtyQueue.clear();
      this._connectionState = "online";
      return { ok: true, pushed: totalDirty };
    } else {
      SyncLog.add("error", "Push ব্যর্থ: " + r.msg);
      this._connectionState = "offline";
      return { ok: false, msg: r.msg };
    }
  },

  // ── batchUpdate — 5s debounce batch write ─────────────────────────────────
  scheduleBatch(collection, records, onFlush) {
    if (!this._batchPending[collection]) this._batchPending[collection] = [];
    for (const rec of records) {
      const idx = this._batchPending[collection].findIndex(r => r.id === rec.id);
      if (idx >= 0) this._batchPending[collection][idx] = rec;
      else this._batchPending[collection].push(rec);
    }
    if (this._batchTimer) clearTimeout(this._batchTimer);
    this._batchTimer = setTimeout(async () => { await this._flushBatch(onFlush); }, 5000);
  },

  async _flushBatch(onFlush) {
    const pending = { ...this._batchPending };
    this._batchPending = {};
    this._batchTimer   = null;
    const totalCount   = Object.values(pending).reduce((s, arr) => s + arr.length, 0);
    if (totalCount === 0) return;
    SyncLog.add("sync", `Batch flush: ${totalCount}টি record`);
    const ts  = new Date().toISOString();
    const key = `batch_${Date.now()}`;
    const r   = await this.set(`dukan/batch/${key}`, {
      data: pending, at: ts, deviceId: DeviceID.get(), vc: VectorClock.get(),
    });
    if (r.ok) {
      SyncLog.add("sync", `✓ Batch write সফল (${totalCount} records)`);
      if (typeof onFlush === "function") onFlush();
    } else {
      SyncLog.add("error", "Batch write ব্যর্থ: " + r.msg);
    }
  },

  // ── Connection latency test ───────────────────────────────────────────────
  async measureLatency() {
    const url = this._url("_ping");
    if (!url) return null;
    const t0 = Date.now();
    try {
      await fetch(url, { method: "PUT", headers: {"Content-Type":"application/json"}, body: JSON.stringify({ ts: t0 }) });
      this._latencyMs       = Date.now() - t0;
      this._connectionState = "online";
      return this._latencyMs;
    } catch {
      this._connectionState = "offline";
      return null;
    }
  },

  getConnectionState() { return this._connectionState; },
  getLatency()         { return this._latencyMs; },
  getConflictLog()     { return [...this._conflictLog]; },
});

// ─── Firebase Phone Auth (REST API — no SDK needed) ──────────────────────────
// Flow: sendOtp() → verifyOtp() → session saved → auto-login on next open
// Requires: Firebase Console → Authentication → Sign-in method → Phone → Enable
const FBAuth = {
  _fmt(phone) {
    const p = phone.replace(/\s|-/g, "");
    return p.startsWith("+") ? p : "+88" + p.replace(/^0/, "");
  },

  // Step 1: Request OTP
  async sendOtp(phone, apiKey) {
    const e164 = this._fmt(phone);
    try {
      const r = await fetch(
        `https://identitytoolkit.googleapis.com/v1/accounts:sendVerificationCode?key=${apiKey}`,
        { method:"POST", headers:{"Content-Type":"application/json"},
          body: JSON.stringify({ phoneNumber: e164, recaptchaToken: "test-reCAPTCHA-token" }) }
      );
      const d = await r.json();
      if (d.sessionInfo) return { ok:true, sessionInfo:d.sessionInfo, phone:e164 };
      const msg = d.error?.message || "OTP পাঠানো যায়নি";
      if (msg.includes("INVALID_PHONE_NUMBER"))  return { ok:false, msg:"মোবাইল নম্বর সঠিক নয়" };
      if (msg.includes("TOO_MANY_ATTEMPTS"))     return { ok:false, msg:"অনেকবার চেষ্টা — পরে আবার চেষ্টা করুন" };
      if (msg.includes("CAPTCHA_CHECK_FAILED"))  return { ok:false, msg:"Firebase Test Phone Number সেট করুন" };
      if (msg.includes("OPERATION_NOT_ALLOWED")) return { ok:false, msg:"Firebase Console-এ Phone Auth চালু করুন" };
      return { ok:false, msg };
    } catch(e) { return { ok:false, msg:"নেটওয়ার্ক সমস্যা: "+e.message }; }
  },

  // Step 2: Verify OTP → get permanent refreshToken
  async verifyOtp(sessionInfo, otp, apiKey) {
    try {
      const r = await fetch(
        `https://identitytoolkit.googleapis.com/v1/accounts:signInWithPhoneNumber?key=${apiKey}`,
        { method:"POST", headers:{"Content-Type":"application/json"},
          body: JSON.stringify({ sessionInfo, code: otp }) }
      );
      const d = await r.json();
      if (d.idToken) return { ok:true, idToken:d.idToken, refreshToken:d.refreshToken, localId:d.localId };
      const msg = d.error?.message || "OTP যাচাই ব্যর্থ";
      if (msg.includes("INVALID_CODE"))    return { ok:false, msg:"OTP ভুল। আবার চেষ্টা করুন।" };
      if (msg.includes("SESSION_EXPIRED")) return { ok:false, msg:"OTP মেয়াদ শেষ। নতুন OTP নিন।" };
      return { ok:false, msg };
    } catch(e) { return { ok:false, msg:"নেটওয়ার্ক সমস্যা: "+e.message }; }
  },

  // Step 3: Silently refresh idToken (called on app start if session exists)
  async refreshIdToken(refreshToken, apiKey) {
    try {
      const r = await fetch(
        `https://securetoken.googleapis.com/v1/token?key=${apiKey}`,
        { method:"POST", headers:{"Content-Type":"application/json"},
          body: JSON.stringify({ grant_type:"refresh_token", refresh_token:refreshToken }) }
      );
      const d = await r.json();
      if (d.id_token) return { ok:true, idToken:d.id_token, refreshToken:d.refresh_token };
      return { ok:false };
    } catch { return { ok:false }; }
  }
};

// ─── Universal Storage Layer (IndexedDB-first, localStorage fallback) ─────────
// IndexedDB: 5000+ customers, 100000+ invoices handle করতে পারে
// Debounced save: প্রতি state change-এ write হয় না, performance বাড়ে
const _memStore = {};

// ── IndexedDB wrapper ──────────────────────────────────────────────────────────
const _idb = (() => {
  let _db = null;
  const DB_NAME = "sbm_db";
  const STORE = "kv";
  const open = () => new Promise((res, rej) => {
    if (_db) return res(_db);
    const req = indexedDB.open(DB_NAME, 1);
    req.onupgradeneeded = e => e.target.result.createObjectStore(STORE);
    req.onsuccess = e => { _db = e.target.result; res(_db); };
    req.onerror   = e => rej(e.target.error);
  });
  return {
    async get(key) {
      try {
        const db = await open();
        return new Promise((res, rej) => {
          const tx = db.transaction(STORE, "readonly");
          const req = tx.objectStore(STORE).get(key);
          req.onsuccess = () => res(req.result ?? null);
          req.onerror   = e => rej(e.target.error);
        });
      } catch { return null; }
    },
    async set(key, val) {
      try {
        const db = await open();
        return new Promise((res, rej) => {
          const tx = db.transaction(STORE, "readwrite");
          tx.objectStore(STORE).put(val, key);
          tx.oncomplete = res;
          tx.onerror    = e => rej(e.target.error);
        });
      } catch {}
    }
  };
})();

const _hasIDB = typeof indexedDB !== "undefined";

const storage = (() => {
  // Claude.ai Artifact environment
  if (typeof window !== "undefined" && window.storage && typeof window.storage.get === "function") {
    return {
      async get(key) {
        try { const r = await window.storage.get(key); return r ? JSON.parse(r.value) : null; } catch { return null; }
      },
      async set(key, val) {
        try { await window.storage.set(key, JSON.stringify(val)); } catch {}
      }
    };
  }
  // React Native with AsyncStorage bridge
  if (typeof window !== "undefined" && window.AsyncStorage) {
    return {
      async get(key) {
        try { const v = await window.AsyncStorage.getItem(key); return v ? JSON.parse(v) : null; } catch { return null; }
      },
      async set(key, val) {
        try { await window.AsyncStorage.setItem(key, JSON.stringify(val)); } catch {}
      }
    };
  }
  // IndexedDB (Android WebView / Chrome — stores large data without 5MB limit)
  if (_hasIDB) {
    return {
      async get(key) {
        try {
          const val = await _idb.get(key);
          if (val !== null) return val;
          // migrate from localStorage if exists
          if (typeof localStorage !== "undefined") {
            const lsVal = localStorage.getItem(key);
            if (lsVal) {
              const parsed = JSON.parse(lsVal);
              await _idb.set(key, parsed);
              try { localStorage.removeItem(key); } catch {}
              return parsed;
            }
          }
          return null;
        } catch { return null; }
      },
      async set(key, val) {
        try { await _idb.set(key, val); } catch {
          // fallback to localStorage
          try { localStorage.setItem(key, JSON.stringify(val)); } catch {}
        }
      }
    };
  }
  // localStorage fallback
  if (typeof window !== "undefined" && window.localStorage) {
    return {
      async get(key) {
        try { const v = localStorage.getItem(key); return v ? JSON.parse(v) : null; } catch { return null; }
      },
      async set(key, val) {
        try { localStorage.setItem(key, JSON.stringify(val)); } catch {}
      }
    };
  }
  // In-memory fallback
  return {
    async get(key) { return _memStore[key] ?? null; },
    async set(key, val) { _memStore[key] = val; }
  };
})();

async function load(key) { try { return await storage.get(key); } catch { return null; } }
async function save(key, val) { try { await storage.set(key, val); } catch {} }

// ── Debounced save: বড় ডেটা (customers, products, invoices) এর জন্য ──────────
// NOTE: module-level fallback — SmartBusinessMgmt uses a useRef-based version
// that properly cleans up on unmount. This is kept only as a safety fallback
// for any code outside the component tree.
function debouncedSave(key, val, delay = 1500) {
  // no-op at module level — component-level version (useRef) takes precedence
  save(key, val); // fallback: immediate save (safe)
}
// ছোট ডেটার (settings, auth) জন্য immediate save থাকে — শুধু বড় ডেটায় debounce

// ─── Password Hashing (Web Crypto API) ───────────────────────────────────────
async function hashPassword(plain) {
  try {
    const enc = new TextEncoder();
    const buf = await crypto.subtle.digest("SHA-256", enc.encode("sbm-salt-v1:" + plain));
    return Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2,"0")).join("");
  } catch {
    let h = 0;
    for (let i = 0; i < plain.length; i++) { h = (Math.imul(31, h) + plain.charCodeAt(i)) | 0; }
    return "fb-" + Math.abs(h).toString(16);
  }
}
async function checkPassword(plain, hash) {
  // Fix 3: robust fallback chain
  if (!plain) return false;
  if (!hash || typeof hash !== "string") return false;
  // Legacy plain-text: hashed passwords are always 64 hex chars (SHA-256)
  if (hash.length !== 64 && !hash.startsWith("fb-")) return plain === hash;
  try {
    return (await hashPassword(plain)) === hash;
  } catch {
    // crypto API unavailable — fallback to plain comparison (should not happen)
    return plain === hash;
  }
}

// ─── SMS Templates ────────────────────────────────────────────────────────────
// Variables: {নাম} {পরিমাণ} {বাকি} {দোকান}
const DEFAULT_SMS_TEMPLATES = {
  baki:   "{দোকান}: {নাম} ভাই, আপনার বাকি ৳{পরিমাণ} যোগ হয়েছে। মোট বাকি: ৳{বাকি}। ধন্যবাদ।",
  joma:   "{দোকান}: {নাম} ভাই, ৳{পরিমাণ} জমা নেওয়া হয়েছে। বর্তমান বাকি: ৳{বাকি}। ধন্যবাদ।",
  custom: "{দোকান}: {নাম} ভাই, আপনার বর্তমান বাকি ৳{বাকি}। ধন্যবাদ।"
};

function applyTemplate(tpl, customer, amount, balance, shopName) {
  return tpl
    .replace(/{দোকান}/g, shopName)
    .replace(/{নাম}/g,    customer.name)
    .replace(/{পরিমাণ}/g, amount)
    .replace(/{বাকি}/g,   balance);
}

// ─── SMS via Claude AI (API Key from Settings) ────────────────────────────────
async function generateSMS(customer, type, amount, balance, shopName, anthropicKey, smsTemplates) {
  const templates = { ...DEFAULT_SMS_TEMPLATES, ...(smsTemplates || {}) };

  if (!anthropicKey) {
    // Use custom template (no API key needed)
    const tpl = templates[type] || templates.custom;
    return applyTemplate(tpl, customer, amount, balance, shopName);
  }
  const prompt = `তুমি একটি ফার্মেসি ম্যানেজমেন্ট সিস্টেম। নিচের তথ্য দিয়ে একটি সংক্ষিপ্ত বাংলা SMS বার্তা তৈরি করো (সর্বোচ্চ ২ লাইন):\nকাস্টমার: ${customer.name}\nলেনদেন: ${type === "baki" ? "বাকি যোগ" : type === "joma" ? "টাকা জমা" : "বিশেষ বার্তা"}\nপরিমান: ৳${amount}\nবর্তমান বাকি: ৳${balance}\nদোকান: ${shopName}\nশুধু SMS টেক্সট দাও।`;
  try {
    const res = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": anthropicKey,
        "anthropic-version": "2023-06-01",
        "anthropic-dangerous-direct-browser-access": "true"
      },
      body: JSON.stringify({ model: "claude-sonnet-4-20250514", max_tokens: 200, messages: [{ role: "user", content: prompt }] })
    });
    if (!res.ok) throw new Error(`API error ${res.status}`);
    const d = await res.json();
    return d.content?.[0]?.text || applyTemplate(templates[type] || templates.custom, customer, amount, balance, shopName);
  } catch {
    return applyTemplate(templates[type] || templates.custom, customer, amount, balance, shopName);
  }
}

// SMS via CapacitorHttp (bypasses WebView CORS) or fetch fallback
async function httpPost(url, headers, body, isForm = false) {
  // Capacitor native HTTP — no CORS issues in APK
  if (typeof window !== "undefined" && window.Capacitor?.isNativePlatform?.()) {
    try {
      const { CapacitorHttp } = await import("@capacitor/core");
      const r = await CapacitorHttp.request({
        method: "POST", url,
        headers: { ...headers, "Content-Type": isForm ? "application/x-www-form-urlencoded" : "application/json" },
        data: isForm ? body : JSON.stringify(body),
      });
      return { ok: r.status >= 200 && r.status < 300, data: r.data, status: r.status };
    } catch {}
  }
  // Browser/fallback fetch
  const res = await fetch(url, {
    method: "POST",
    headers: { ...headers, "Content-Type": isForm ? "application/x-www-form-urlencoded" : "application/json" },
    body: isForm ? (typeof body === "string" ? body : new URLSearchParams(body).toString()) : JSON.stringify(body),
  });
  const text = await res.text();
  let data; try { data = JSON.parse(text); } catch { data = text; }
  return { ok: res.ok, data, status: res.status };
}

async function httpGet(url) {
  if (typeof window !== "undefined" && window.Capacitor?.isNativePlatform?.()) {
    try {
      const { CapacitorHttp } = await import("@capacitor/core");
      const r = await CapacitorHttp.request({ method: "GET", url });
      return { ok: r.status < 300, data: r.data };
    } catch {}
  }
  const res = await fetch(url);
  const text = await res.text();
  return { ok: res.ok, data: text };
}

async function sendRealSMS(mobile, message, gateway) {
  if (!gateway?.apiKey || !gateway?.provider) return { success: false, error: "গেটওয়ে সেট করা নেই" };
  try {
    if (gateway.provider === "twilio") {
      const auth = "Basic " + btoa(`${gateway.accountSid}:${gateway.apiKey}`);
      const r = await httpPost(
        `https://api.twilio.com/2010-04-01/Accounts/${gateway.accountSid}/Messages.json`,
        { Authorization: auth }, `To=${encodeURIComponent(mobile)}&From=${encodeURIComponent(gateway.senderId)}&Body=${encodeURIComponent(message)}`,
        true
      );
      if (r.ok) return { success: true };
      const d = typeof r.data === "string" ? JSON.parse(r.data) : r.data;
      return { success: false, error: d?.message || "Twilio error" };
    }
    if (gateway.provider === "ssl") {
      const url = `https://sms.sslwireless.com/pushapi/dynamic/server.php?user=${gateway.username}&pass=${gateway.apiKey}&sms=${encodeURIComponent(message)}&mobile=${mobile}&sid=${gateway.senderId}`;
      const r = await httpGet(url);
      return String(r.data).includes("SUCCESS") ? { success: true } : { success: false, error: String(r.data).slice(0, 80) };
    }
    if (gateway.provider === "alpha") {
      // Alpha SMS (Bangladesh)
      const url = `https://bulksmsbd.net/api/smsapi?api_key=${gateway.apiKey}&type=text&number=${mobile}&senderid=${gateway.senderId}&message=${encodeURIComponent(message)}`;
      const r = await httpGet(url);
      return r.ok ? { success: true } : { success: false, error: String(r.data).slice(0, 80) };
    }
    if (gateway.provider === "bulksms") {
      // BulkSMSBD (Bangladesh)
      const url = `https://bulksmsbd.net/api/smsapi?api_key=${gateway.apiKey}&type=text&number=${mobile}&senderid=${gateway.senderId}&message=${encodeURIComponent(message)}`;
      const r = await httpGet(url);
      return r.ok ? { success: true } : { success: false, error: String(r.data).slice(0, 80) };
    }
    return { success: false, error: "অজানা গেটওয়ে" };
  } catch (e) { return { success: false, error: e.message }; }
}

// ─── ESC/POS Bluetooth Thermal Printer ───────────────────────────────────────
// Tested with: Xprinter, Sewoo, GOOJPRT, MUNBYN, and most BLE thermal printers
// Bengali text requires the printer firmware to support UTF-8 (most 2022+ models do)

const BT_SERVICE_UUIDS = [
  "000018f0-0000-1000-8000-00805f9b34fb", // Generic POS / Xprinter
  "e7810a71-73ae-499d-8c15-faa9aef0c3f2", // Epson/STAR BLE
  "0000ff00-0000-1000-8000-00805f9b34fb", // GOOJPRT / MUNBYN
  "49535343-fe7d-4ae5-8fa9-9fafd205e455", // Microchip BM70/RN4870
];
const BT_CHAR_UUIDS = [
  "000018f1-0000-1000-8000-00805f9b34fb",
  "bef8d6c9-9c21-4c9e-b632-bd58c1009f9f",
  "0000ff02-0000-1000-8000-00805f9b34fb",
  "49535343-8841-43f4-a8d4-ecbe34729bb3",
];

function buildEscPosBuffer(inv, shopName) {
  const enc = new TextEncoder(); // UTF-8
  const [ESC, GS, LF] = [0x1B, 0x1D, 0x0A];
  const out = [];
  const push  = (...b) => b.forEach(x => out.push(x));
  const write = (s)    => enc.encode(String(s)).forEach(b => out.push(b));
  const nl    = ()     => out.push(LF);
  const bold  = (on)   => push(ESC, 0x45, on ? 1 : 0);
  const align = (a)    => push(ESC, 0x61, a); // 0=left 1=center 2=right
  const size  = (dbl)  => push(ESC, 0x21, dbl ? 0x30 : 0x00);

  push(ESC, 0x40);        // Initialize printer
  push(ESC, 0x74, 0x00);  // Code page – some printers need this; UTF-8 handled by TextEncoder

  // ── Header ──
  align(1); size(true); bold(true);
  write(shopName || "SBM"); nl();
  size(false); bold(false);
  write("--------------------------------"); nl();
  write("Invoice #" + ((inv.id || "").slice(0, 8).toUpperCase())); nl();
  write(inv.date || ""); nl();

  // ── Customer ──
  align(0);
  write("--------------------------------"); nl();
  write("কাস্টমার : " + inv.customerName); nl();
  write("মোবাইল   : " + inv.customerMobile); nl();
  write("--------------------------------"); nl();

  // ── Items header ──
  write("পণ্য              Qty    মোট"); nl();
  write("--------------------------------"); nl();

  (inv.items || []).forEach(item => {
    const name  = (item.name || "").slice(0, 16).padEnd(17);
    const qty   = String(item.qty).padEnd(6);
    const total = "৳" + (item.qty * item.price);
    write(name + qty + total); nl();
  });

  // ── Totals ──
  write("--------------------------------"); nl();
  if ((inv.discount||0) > 0 || (inv.extraCharge||0) > 0) {
    align(2);
    write("সর্বমোট: ৳" + (inv.subtotal || inv.total)); nl();
    if ((inv.discount||0) > 0) { write("ডিসকাউন্ট: -৳" + inv.discount); nl(); }
    if ((inv.extraCharge||0) > 0) { write("অতিরিক্ত চার্জ: +৳" + inv.extraCharge); nl(); }
  }
  align(2); bold(true); size(true);
  write("মোট: ৳" + inv.total); nl();
  size(false); bold(false);

  if (inv.payType === "partial") {
    write("নগদ : ৳" + (inv.paidAmount || 0)); nl();
    write("বাকি: ৳" + (inv.bakiAmount || 0)); nl();
  } else {
    write(inv.payType === "baki" ? "বাকিতে দেওয়া হয়েছে" : "নগদ পরিশোধ"); nl();
  }

  // ── Footer ──
  align(1);
  nl(); write("ধন্যবাদ! আবার আসবেন"); nl();
  nl(); nl(); nl();
  push(GS, 0x56, 0x41, 0x10); // Partial cut

  return new Uint8Array(out);
}

async function sendEscPosBluetooth(btDevice, inv, shopName) {
  if (!btDevice) throw new Error("কোনো প্রিন্টার নির্বাচন করা হয়নি");

  let server;
  try { server = btDevice.gatt.connected ? btDevice.gatt : await btDevice.gatt.connect(); }
  catch { throw new Error("প্রিন্টার পুনরায় সংযোগ ব্যর্থ হয়েছে"); }

  let service = null;
  for (const sid of BT_SERVICE_UUIDS) {
    try { service = await server.getPrimaryService(sid); break; } catch {}
  }
  if (!service) throw new Error("প্রিন্টার সার্ভিস খুঁজে পাওয়া যায়নি। প্রিন্টার মডেল নিশ্চিত করুন।");

  let char = null;
  for (const cid of BT_CHAR_UUIDS) {
    try { char = await service.getCharacteristic(cid); break; } catch {}
  }
  if (!char) throw new Error("প্রিন্ট চ্যারেকটেরিস্টিক পাওয়া যায়নি");

  const data  = buildEscPosBuffer(inv, shopName);
  const CHUNK = 200; // safe BLE chunk size
  for (let i = 0; i < data.length; i += CHUNK) {
    await char.writeValueWithoutResponse(data.slice(i, i + CHUNK));
    await new Promise(r => setTimeout(r, 30));
  }
}
// navigator.bluetooth is NOT available in React Native WebView or all Android browsers.
// We detect the environment and show the right message.
const btSupported = (typeof window !== "undefined" && !!window.Capacitor?.isNativePlatform?.())
  || (typeof navigator !== "undefined" && !!navigator.bluetooth);

// Print helper — falls back gracefully when window.open is unavailable (some WebViews)
function openPrintWindow(htmlContent, onBack) {
  // Artifact environment (window.storage exists) — srcdoc sandbox blocked, use new tab
  if (typeof window !== "undefined" && window.storage && typeof window.storage.get === "function") {
    const win = window.open("", "_blank");
    if (win) {
      win.document.open();
      win.document.write(htmlContent);
      win.document.close();
      return;
    }
  }
  // Native APK + Browser: always use in-app overlay with srcdoc
  _showPrintOverlay(htmlContent, onBack);
}

// In-app print overlay (WebView fallback)
function _showPrintOverlay(htmlContent, onBack) {
  const existing = document.getElementById("__print_overlay__");
  if (existing) existing.remove();
  const overlay = document.createElement("div");
  overlay.id = "__print_overlay__";
  overlay.style.cssText = "position:fixed;inset:0;background:#fff;z-index:9999;display:flex;flex-direction:column;";
  const toolbar = document.createElement("div");
  toolbar.style.cssText = "background:#1a1a2e;padding:10px 16px;display:flex;align-items:center;gap:10px;flex-shrink:0;flex-wrap:wrap;";
  toolbar.innerHTML = `<button id="__print_back__" style="background:#22c55e;color:#fff;border:none;border-radius:8px;padding:8px 14px;font-size:13px;font-weight:700;cursor:pointer;font-family:inherit;">← ফিরুন</button>
    <button id="__print_btn__" style="background:#3b82f6;color:#fff;border:none;border-radius:8px;padding:8px 14px;font-size:13px;font-weight:700;cursor:pointer;font-family:inherit;">🖨️ Print</button>
    <button id="__pdf_dl_btn__" style="background:#7c3aed;color:#fff;border:none;border-radius:8px;padding:8px 14px;font-size:13px;font-weight:700;cursor:pointer;font-family:inherit;">📥 PDF সেভ</button>`;
  const frame = document.createElement("iframe");
  frame.style.cssText = "flex:1;border:none;width:100%;";
  // srcdoc ব্যবহার: WebView-এ contentDocument.write CORS block করে, srcdoc করে না
  frame.srcdoc = htmlContent;
  overlay.appendChild(toolbar);
  overlay.appendChild(frame);
  document.body.appendChild(overlay);
  document.getElementById("__print_back__").onclick = () => { overlay.remove(); if (typeof onBack === "function") onBack(); };
  document.getElementById("__print_btn__").onclick = () => { try { frame.contentWindow.print(); } catch {} };
  document.getElementById("__pdf_dl_btn__").onclick = async () => {
    const btn = document.getElementById("__pdf_dl_btn__");
    if (btn) { btn.disabled = true; btn.textContent = "⏳ তৈরি হচ্ছে..."; }
    const result = await downloadAsPdf(htmlContent, "SBM_ফাইল_" + Date.now());
    if (btn) { btn.disabled = false; btn.textContent = "📥 PDF সেভ"; }
    if (result.msg) alert(result.msg);
  };
}

