function buildDailyListHtml(items, listType, shopName) {
  let rows = "";
  let totalAmt = 0;
  if (listType === "payment-receipts") {
    // জমার তালিকা
    rows = items.map((item, i) => {
      totalAmt += item.amount || 0;
      const prevBal = (item.remainingBalance || 0) + (item.amount || 0);
      return `<tr>
        <td class="serial">${i+1}</td>
        <td>${item.customerName || "—"}</td>
        <td>${item.customerMobile || "—"}</td>
        <td>${item.time || item.date || "—"}</td>
        <td class="amount" style="color:#f59e0b;font-weight:700;">৳${prevBal.toLocaleString("en-US")}</td>
        <td class="amount">৳${(item.amount||0).toLocaleString("en-US")}</td>
        <td class="amount" style="color:#ef4444;font-weight:700;">৳${(item.remainingBalance||0).toLocaleString("en-US")}</td>
      </tr>`;
    }).join("");
    const thead = `<tr><th class="serial">#</th><th>কাস্টমার</th><th>মোবাইল</th><th>সময়</th><th class="num" style="color:#f59e0b;">পূর্বের বাকি</th><th class="num">জমা</th><th class="num">বর্তমান বাকি</th></tr>`;
    const tfooter = `<tr class="total-row"><td class="serial">—</td><td colspan="4">মোট জমা</td><td class="amount">৳${totalAmt.toLocaleString("en-US")}</td><td></td></tr>`;
    return `<table><thead>${thead}</thead><tbody>${rows}${tfooter}</tbody></table>`;
  } else {
    // ইনভয়েস তালিকা
    rows = items.map((item, i) => {
      totalAmt += item.total || 0;
      const badge = item.payType === "baki" ? `<span class="badge baki">বাকি</span>` : item.payType === "partial" ? `<span class="badge partial">আংশিক</span>` : `<span class="badge cash">নগদ</span>`;
      return `<tr>
        <td class="serial">${i+1}</td>
        <td>${item.customerName || "—"}</td>
        <td>${item.customerMobile || "—"}</td>
        <td>${item.date || "—"}</td>
        <td>${badge}</td>
        <td class="amount">৳${(item.total||0).toLocaleString("en-US")}</td>
      </tr>`;
    }).join("");
    const thead = `<tr><th class="serial">#</th><th>কাস্টমার</th><th>মোবাইল</th><th>তারিখ</th><th>ধরন</th><th class="num">পরিমাণ</th></tr>`;
    const tfooter = `<tr class="total-row"><td class="serial">—</td><td colspan="4">মোট</td><td class="amount">৳${totalAmt.toLocaleString("en-US")}</td></tr>`;
    return `<table><thead>${thead}</thead><tbody>${rows}${tfooter}</tbody></table>`;
  }
}

// ── Customer History PDF Builder ──────────────────────────────────────────
function buildCustomerHistoryHtml(customer, txns, invoices, paymentInvoices, months, shopName) {
  const now = new Date();
  const cutoff = new Date(now.getFullYear(), now.getMonth() - months, 1);
  const filtered = txns.filter(t => {
    try { return new Date(t.dateKey || t.date) >= cutoff; } catch { return true; }
  });
  let rows = "";
  filtered.forEach((t, i) => {
    const isBaki = t.type === "baki";
    const isVoidRev = t.source === "void-reversal";
    // পূর্বের বাকি = balanceAfter - amount (বাকি হলে), balanceAfter + amount (জমা হলে)
    const prevBal = isBaki
      ? (t.balanceAfter || 0) - (t.amount || 0)
      : (t.balanceAfter || 0) + (t.amount || 0);
    const typeLabel = isBaki
      ? `<span class="badge baki">▲ বাকি</span>`
      : isVoidRev
        ? `<span class="badge joma" style="background:#f59e0b22;color:#f59e0b;border-color:#f59e0b44;">▼ জমা <small style="font-size:9px;">(বাতিল)</small></span>`
        : `<span class="badge joma">▼ জমা</span>`;
    rows += `<tr>
      <td class="serial">${i+1}</td>
      <td>${t.date || "—"}</td>
      <td>${typeLabel}</td>
      <td class="amount" style="color:#f59e0b;font-weight:700;">৳${prevBal.toLocaleString("en-US")}</td>
      <td class="amount" style="color:${isBaki?"#ef4444":"#22c55e"}">${isBaki?"+":"-"}৳${(t.amount||0).toLocaleString("en-US")}</td>
      <td class="amount" style="color:${(t.balanceAfter||0)>0?"#ef4444":"#22c55e"};font-weight:700;">৳${(t.balanceAfter||0).toLocaleString("en-US")}</td>
    </tr>`;
  });
  const summary = `
    <div style="background:linear-gradient(135deg,#0369a115,#0ea5e910);border:1.5px solid #0369a133;border-radius:14px;padding:16px 20px;margin-bottom:16px;">
      <div style="display:flex;gap:12px;align-items:center;flex-wrap:wrap;">
        <div style="flex:1;min-width:200px;">
          <div style="font-weight:900;font-size:18px;">${customer.name}</div>
          <div style="color:#666;font-size:12px;margin-top:2px;">${customer.mobile||""}</div>
          <div style="color:#666;font-size:12px;">${customer.address||""}</div>
        </div>
        <div style="background:#ef444415;border-radius:10px;padding:12px 18px;text-align:center;min-width:130px;">
          <div style="color:#ef4444;font-size:11px;font-weight:700;">বর্তমান বাকি</div>
          <div style="font-weight:900;font-size:22px;color:#ef4444;">৳${(customer.balance||0).toLocaleString("en-US")}</div>
        </div>
      </div>
    </div>`;
  const thead = `<tr><th class="serial">#</th><th>তারিখ</th><th>ধরন</th><th class="num" style="color:#f59e0b;">পূর্বের বাকি</th><th class="num">পরিমাণ</th><th class="num">বর্তমান বাকি</th></tr>`;
  const table = filtered.length > 0
    ? `<table><thead>${thead}</thead><tbody>${rows}</tbody></table>`
    : `<div style="text-align:center;padding:30px;color:#999;">এই সময়কালে কোনো লেনদেন নেই</div>`;
  return summary + table;
}

// ── PDF Action Buttons Component ──────────────────────────────────────────────
// ─── DashModalDateRangePicker — ডিটেইলস পেজে তারিখ রেঞ্জ সিলেক্টর ────────────
const DASH_MODAL_RANGES = [
  { key: "today",     label: "আজ" },
  { key: "yesterday", label: "গতকাল" },
  { key: "week",      label: "এই সপ্তাহ" },
  { key: "month",     label: "এই মাস" },
  { key: "custom",    label: "📅 কাস্টম" },
];

function useDashModalRange() {
  const [range, setRange]       = React.useState("today");
  const [customDate, setCD]     = React.useState(() => new Date().toISOString().slice(0, 10));

  const todayKey = new Date().toISOString().slice(0, 10);
  const toKey    = (d) => d.toISOString().slice(0, 10);

  let startKey, endKey, label;
  const now = new Date();
  if (range === "today") {
    startKey = endKey = todayKey; label = "আজকের";
  } else if (range === "yesterday") {
    const y = new Date(now); y.setDate(y.getDate() - 1);
    startKey = endKey = toKey(y); label = "গতকালের";
  } else if (range === "week") {
    const dow = now.getDay(); // 0=Sun
    const mon = new Date(now); mon.setDate(now.getDate() - dow);
    startKey = toKey(mon); endKey = todayKey; label = "এই সপ্তাহের";
  } else if (range === "month") {
    const m = new Date(now.getFullYear(), now.getMonth(), 1);
    startKey = toKey(m); endKey = todayKey; label = "এই মাসের";
  } else {
    startKey = endKey = customDate || todayKey;
    const dateLabel = (() => {
      try { return new Date(startKey + "T00:00:00").toLocaleDateString("en-US", { day: "numeric", month: "long", year: "numeric" }); }
      catch { return startKey; }
    })();
    label = startKey === todayKey ? "আজকের" : `${dateLabel} তারিখের`;
  }

  const inRange = (dk) => dk >= startKey && dk <= endKey;
  const shiftCustomDate = (days) => {
    const d = new Date((customDate || todayKey) + "T00:00:00");
    d.setDate(d.getDate() + days);
    const nk = toKey(d);
    if (nk <= todayKey) setCD(nk);
  };
  return { range, setRange, customDate, setCD, shiftCustomDate, startKey, endKey, label, inRange, todayKey };
}

function DashModalDateRangePicker({ hook, accentColor = "#1fd15e", T }) {
  const { range, setRange, customDate, setCD, shiftCustomDate, todayKey } = hook;
  const isCustomToday = customDate === todayKey;
  return (
    <div style={{ marginBottom: 12 }}>
      <div style={{ display:"flex", gap:5, overflowX:"auto", paddingBottom:4, WebkitOverflowScrolling:"touch", scrollbarWidth:"none" }}>
        {DASH_MODAL_RANGES.map(r => (
          <button key={r.key} onClick={() => setRange(r.key)}
            style={{
              flexShrink:0, padding:"6px 12px", borderRadius:20, fontSize:11, fontWeight:800,
              fontFamily:"inherit", cursor:"pointer", whiteSpace:"nowrap", border:"none",
              background: range === r.key ? `linear-gradient(135deg,${accentColor},${accentColor}cc)` : "rgba(255,255,255,0.06)",
              color: range === r.key ? "#04210f" : "#94a3b8",
              boxShadow: range === r.key ? `0 2px 10px ${accentColor}44` : "none",
              transition: "all 0.15s",
            }}>
            {r.label}
          </button>
        ))}
      </div>
      {range === "custom" && (
        <div style={{ display:"flex", alignItems:"center", gap:8, marginTop:8, background:"rgba(255,255,255,0.03)", border:`1px solid ${accentColor}33`, borderRadius:14, padding:"8px 10px" }}>
          <button onClick={() => shiftCustomDate(-1)}
            style={{ width:34, height:34, borderRadius:10, background:`${accentColor}1f`, border:`1px solid ${accentColor}4d`, color:"#fff", fontSize:16, fontWeight:900, cursor:"pointer", flexShrink:0 }}>‹</button>
          <input type="date" value={customDate} max={todayKey}
            onChange={e => e.target.value && setCD(e.target.value)}
            style={{ flex:1, background:"transparent", color:"#fff", border:"none",
              fontSize:12, fontWeight:800, fontFamily:"inherit", colorScheme:"dark", textAlign:"center", cursor:"pointer" }} />
          <button onClick={() => shiftCustomDate(1)} disabled={isCustomToday}
            style={{ width:34, height:34, borderRadius:10, background:`${accentColor}1f`, border:`1px solid ${accentColor}4d`, color: isCustomToday ? "#4b4566" : "#fff", fontSize:16, fontWeight:900, cursor: isCustomToday ? "default" : "pointer", flexShrink:0 }}>›</button>
        </div>
      )}
    </div>
  );
}
