// ─── Shared Profit Utilities ──────────────────────────────────────────────────
// সব জায়গায় একই formula: cost = it.costPrice ?? p.costPrice ?? 0 (invoice-time দাম আগে)
//                          revenue = inv.total (discount-পরবর্তী)
// per-item breakdown-এ revenue discount অনুপাতে scale হয় যাতে যোগফল inv.total-এর সাথে মেলে
const _itemCostPrice = (item, prodMap) =>
  (item.costPrice != null) ? item.costPrice : (prodMap?.get?.(item.productId)?.costPrice ?? 0);

const calcInvoiceProfit = (inv, prodMap) => {
  const items = inv.items || [];
  const subtotal = items.reduce((s, it) => s + (it.price || 0) * (it.qty || 1), 0);
  const discountRatio = subtotal > 0 ? (inv.total || 0) / subtotal : 1;
  return items.reduce((s, it) => {
    const qty = it.qty || 1;
    const revenue = (it.price || 0) * qty * discountRatio; // discount-adjusted
    const cost = _itemCostPrice(it, prodMap) * qty;
    return s + revenue - cost;
  }, 0);
};

const calcProfitTotal = (invList, prodMap) =>
  invList.reduce((s, inv) => s + calcInvoiceProfit(inv, prodMap), 0);

// per-product breakdown with discount-scaled revenue
const calcProfitByProduct = (invList, prodMap, productsFallback = []) => {
  const map = {};
  invList.forEach(inv => {
    const items = inv.items || [];
    const subtotal = items.reduce((s, it) => s + (it.price || 0) * (it.qty || 1), 0);
    const discountRatio = subtotal > 0 ? (inv.total || 0) / subtotal : 1;
    items.forEach(item => {
      const qty = item.qty || 1;
      const p = prodMap?.get?.(item.productId) || productsFallback.find(pr => pr.name === item.name);
      const cost = _itemCostPrice(item, prodMap) * qty;
      const revenue = (item.price || 0) * qty * discountRatio;
      const profit = revenue - cost;
      // productId দিয়ে গ্রুপ করা হয় যাতে পণ্যের নাম পরে এডিট/পরিবর্তন হলেও পুরোনো ও নতুন ইনভয়েসের বিক্রি একই সারিতে মিলে যায়
      const key = item.productId || item.name;
      const displayName = p?.name || item.name;
      if (!map[key]) map[key] = { name: displayName, qty: 0, revenue: 0, cost: 0, profit: 0 };
      map[key].name = displayName; // সবসময় পণ্যের সর্বশেষ/বর্তমান নাম দেখাবে
      map[key].qty += qty;
      map[key].revenue += revenue;
      map[key].cost += cost;
      map[key].profit += profit;
    });
  });
  return Object.values(map);
};

