  const detailCust = showDetail ? customers.find(c => c.id === detailCId) : null;

  const tabTitles = { customers:"কাস্টমার", invoice:"নতুন ইনভয়েস", products:"ওষুধ তালিকা", settings:"সেটিং", ai:"AI ও অটোমেশন" };

